window.copticPsalms = {
  "1": "طُوبَى للرَّجُلِ طُوبَى للرَّجُلِ الذِى لَمْ يَسْلكْ فى مَشُورةِ المنَافِقِينَ. وفى طَريقِ الَخُطَاةِ لَمْ يَقِف، وفى مَجْلسِ المسْتَهزِئينَ لَمْ يَجِلسْ. لكنْ فى نَامُوسِ الرَّبِّ إرادَتُه، وفى نَامُوسِهِ يَلْهجُ نَهاراً وليْلاً. فيَكونُ كالشجَرةِ المغْروسَةِ عَلى مَجارِى المياهِ، التِى تُعْطِى ثَمَرَها فى حِينِهِ. وَورَقُها لا ينْتَثِرُ، وكلُّ ما يَصْنعُ ينْجَحُ فِيهِ. لَيسَ كَذلِكَ المنَافِقُونَ، لَيسَ كَذلَكَ. لكنَّهمْ كالَهَبَاءِ الذِى تَذْرِيهِ الرِّيحُ عَنْ وجُهِ الأرْضِ. فَلهَذَا لا يَقومُ المنَافِقُونَ فى الدَّينُونَةِ، ولاَ الخُطَاةُ فى مَجْمَعِ الصِّدِّيقينَ. لأنَّ الرَّبَّ يَعْرِفُ طَريقَ الأبْرارِ، وأمَّا طَرِيقُ المنَافِقينَ فَتُبادُ. هَلِّلُيلويا. + +++",
  "2": "لِماذَا ارْتَجَّت الأمَمُ لِماذَا ارْتَجَّت الأمَمُ، وفَكَّرت الشُّعوبُ بالبَاطِل. قَامَ مُلوكُ الأرْضِ، وتآمَرَ الرُّؤساءُ مَعاً عَلى الرَّبِّ وعَلىِ مَسِيحِهِ قائِلينَ: لِنَقْطَعْ أغْلالَهُم، ولِنَطرحْ عنَّا نَيْرهَا. السَاكِنُ فى السَّمَواتِ يَضْحَكُ بِهِم، والرَّبُّ يَمْقُتُهُم. حِينَئذٍ يُكلِّمهُم بغَضَبهِ، وبِرَجزِهِ يُقْلقُهمْ. أنَا أقَمْتهُ مَلكاً عَلى صُهْيون جَبَل قُدْسهِ، لأكُرِزَ بأَمْر الرَّبِّ. الرَّبُّ قالَ لِى: أنْتَ ابْنِى، وأنَاَ اليَومَ وَلدْتُك. سَلْنِى فأُعْطِيكَ الأُمَمَ مِيرَاثَكَ، وسُلْطانَكَ إلَى أقْطارِ الأرْضِ. لترْعَاهُم بقضِيبٍ مِنْ حَديدٍ. ومِثْل آنِيةِ الفَخَّارِ تَسْحقُهمْ. فالآنَ أيُّهَا الملُوكُ إفْهَموا، تأدَّبُوا ياجَميعَ قَضَاةِ الأرْضِ اعْبدُوا الرَّبَّ بَخَشْيةِ. وهَلِّلُوا لَهُ برعْدَةٍ. الْزَمُوا الأدَبَ لِئلاَّ يغْضَبَ الرَّبُّ فتَضِلُّوا عَنْ طَريقِ الحَقِّ. عِنْدمَا يتَّقدُ غَضَبُه بسُرْعةٍ. طُوبَى لجَمِيع المتَّكلِينَ عَليْهِ. هَلِّلُيلويا. + +++",
  "3": "يَارَبُّ لماذَا كَثُرَ يَارَبُّ لماذَا كَثُرَ الذِينَ يُحزْنُونِى، كَثِيرونَ قامُوا علىَّ. كَثِيرونَ يقُولُونَ لِنفْسِى، لَيسَ لَهُ خَلاصٌ بإلَهِهِ. أنْتَ يارَبّ أنْتَ هُو نَاصِرِى، مَجْدِى ورَافِعُ رَأسِى. بصَوْتى إلَى الرَّبِّ صَرخْتُ. فإسْتَجابَ لِى مِنْ جَبَلِ قُدْسه. أنَا اضْطَجَعتُ ونِمْتُ ثمَّ اسْتَيقظْتُ لأنَّ الرَّبَّ نَاصِرى. فَلاَ أخَافَ مِنْ رَبَوات الَجُمُوع المُحِيطِينَ بى القَائميِنَ عَلَىِّ. قُمْ يَارَبّ خلِّصْنِى يَا إلَهِى، لأنَّكَ ضَرَبْتَ كُلَّ مِنْ يُعادِينى بَاطِلاً. أسْنانُ الخُطاةِ سَحَقَتَها. للرَّبِّ الخَلاَص وعَلَى شَعبِه بَرَكتهُ. هَلِّلُيلويا. + +++",
  "4": "إذْ دَعَوْتُ اسْتَجَبْتَ لِى إذْ دَعَوْتُ اسْتَجَبْتَ لِى يَا إلهَ برِّى، فى الشّدَّةِ فَرَّجتَ عَنِّى. تَراءَفْ عَلىَّ يَا رَبُّ وإسْمَعْ صَلاتِى. يا بَنِى البَشَرَ حتَّى مَتَى تَثْقلُ قلُوبُكُم؟ لماذَا تُحبُّونَ البَاطِلَ وتَبْتَغونَ الكَذبَ؟ اعْلمُوا أنَّ الرَّبَّ قَدْ جَعَلَ قُدُّوسَه عَجباً. الرَّبُّ يَسْتَجيبُ لِى إذا ما صَرخْتُ إلَيهِ. اغْضَبُوا ولا تُخْطِئوا. الذِى تَقولُونَه فى قُلوبِكُم انْدمُوا عَليْهِ فى مَضَاجِعكُم. اذْبَحُوا ذَبيحَة البِرِّ، وتَوكَّلُوا عَلى الرَّبِّ. كَثيرُونَ يقُولُونَ مَنْ يُرينَا الخَيْرات؟ قَدْ أضَاءَ عَلَينَا نُورَ وجْهكَ يَا ربُّ. أعْطَيتَ سُرُوراً لِقلْبِى أوْفَرَ مِنَ الذِينَ كَثُرتْ حِنْطَتهُمْ وخَمْرُهُم وزَيتُهُم. فَبالسَّلامِ أضْطَجعُ أيْضاً وأنَام، لأنَّكَ أنْتَ وحْدَك ياربُّ أسْكَنتَنِى علَى الرَّجَاء. هَلِّلُيلويا. + +++",
  "5": "انًصِتْ يَارَبُّ لِكَلِماتِى انًصِتْ يَارَبُّ لِكَلِماتِى، واسْمَعْ صُراخِى. اصْغ إلى صَوْتِ طَلبَتى يامَلِكى وإلَهِى، لأنِّى إليْكَ أصلِّى. يارَبُّ بالغّداةِ تَسمَعُ صَوتِى، بالغَداةِ أقف أمَامكَ وتَرانِى. لأنَّكَ إلهٌ لا تَشَاء الإثْمَ، ولا يُساكِنُكَ مَنْ يَصنَعُ الشَّرَّ. ولا يَثْبتُ مُخالفُو النَّامُوس أمَامَ عَيْنَيكَ. يَاربُّ أبْغَضتَ جَمِيعَ فَاعِلِى الأثْمِ، وتُهِلكُ كلَّ النَّاطِقينَ بالكَذبِ. رَجلُ الدِّماءِ والغاشِّ يَرذلُهُ الرَّبُّ. أمَّا أنَا فبكثْرةِ رحْمَتكَ أدْخلُ بَيْتَكَ، وأسْجدُ قَدَّامَ هَيْكلِ قُدسِك بَمَخَافَتكَ. ياربُّ اهْدِنِى بِبرِّكَ. مِنْ أجْل أعْدائِى، سَهِّلْ أمَامِى طَريقَكَ. لأنَّهُ لَيسَ فى أفْواهِهِمْ صِدقٌ. بَاطِلٌ هُوَ قَلبُهُمِ. حَنْجرتَهُمْ قَبْرٌ مفْتُوحٌ. وبألسِنتِهم قد غَشُّوا. دِنْهُمْ يا الله. وليسْقُطُوا مِنْ جَميعِ مُؤامَراتِهِمْ وكِكَثْرةِ نِفاقِهِمْ اسْتَأصِلْهُم، لأنَّهُم قَدْ أغْضَبوكَ يَاربُّ. وليَفْرحْ جَميعُ المتَّكلِينَ عَليكَ، إلى الأبَدِ يُسرُّونَ وتَحلُّ فِيهِمْ. ويفْتَخرُ بكَ كلُّ الذِينَ يُحبُّونَ إسْمكَ. لأنَّكَ أنْتَ بَارَكتَ الصِّدِّيقَ يَا ربُّ. كَما بِتُرْسِ المسَرَّةِ كَلَلتَنَا. هَلِّلُيلويا. + +++",
  "6": "يَاربُّ لا تُبكِّتْنِى بغَضَبكَ يَا ربُّ لا تُبكِّتْنِى بغَضَبكَ، ولا تُؤدِّبْنِى بسُخْطكَ. ارْحَمنِى يَاربُّ فإنِّى ضَعِيفٌ، اشْفِنِى يارَبُّ فإنَّ عِظَامِى قَد اضْطَربَتْ ونَفْسِى قدِ انْزَعجَت جِدّاً. وأنْتَ يَاربُّ فإلَى مَتَى؟ عُدْ ونَجِّى نَفْسى، واحْيِنِى مِنْ أجْلِ رَحْمتكَ. لأنَّه لَيسَ فى الموْتِ مِنْ يَذْكُركَ ولا فى الَجَحِيم مَنْ يَعْترفُ لَك. تَعِبتُ فى تَنهُّدِى. أُعَوِّمُ كلَّ لَيلةٍ سَرِيرِى، وبدُمُوعِى أبلُّ فِراشِى. تَعكَّرتْ مِنَ الغَضَبِ عَيْناىَ. هُرِمتُ مِنْ سَائِرِ أعْدائِى. ابْعُدوا عَنِّى يَا جَميعَ فَاعِلى الإثْمِ لأنَّ الرَّبَّ قَد سَمِعَ صَوتَ بُكائِى. الرَّبُّ سَمِعَ تَضرُّعِىِ، الرَّبُّ لِصَلاتِى قَبِلَ، فَلْيَخزَ ولْيضْطَربَ جدًا جَميعُ أعْدائى، ولْيرتدُّوا إلى ورَائِهِمْ بالخِزْى سَريعاً جِدِّا. هَلِّلُيلويا. + +++",
  "8": "أيُّهَا الرَّبُّ رَبُّنَا أيُّهَا الرَّبُّ رَبُّنَا ما أعْجَب اسْمَكَ عَلَى الأرْضِ كلِّهَا، لأنَّهُ قَدِ ارْتفَعَ عِظَمُ جَلالِكَ فَوْقَ السَّمواتِ. مِنْ أفْواهِ الأطْفالِ والرُّضْعانِ هَيَّأتَ سُبْحاً، مِنْ أجْلِ أعْدائِكَ لتُسِكتَ عَدوّاً ومُنْتَقماً. لأنَّى أرَى السَّمواتِ أعْمَالَ يَديْكَ، القَمَرَ والنُّجومَ أنْتَ أسَّسْتَها. مَنْ هُوَ الإنْسانُ حتَّى تَذْكَرهُ. وابْنُ الإنْسانِ حَتَّى تَفْتَقِدهُ؟ أنْقَصتَهُ قَليلاً عَنِ الملائِكَةِ. بالَمجْدِ والكَرامَةِ تَوُّجْتهُ، وعَلَىِ أعْمَالِ يَدَيْكَ أقَمْتهُ. كلُّ شَئٍ أخْضَعْتَ تَحْتَ قَدَميْهِ. الغَنَمَ والبَقَرَ جَميِعاً وأيْضاً بَهَائِمَ الحَقْل، وطُيورَ السَّماءِ وأسْمَاكَ البَحْر السَّالِكَة فى البِحار. أيُّها الرَّبُّ ربُّنَا، مَا أعْجَبَ اسْمَكَ فى الأرْضِ كلِّها. هَلِّلُيلويا. + +++",
  "11": "خَلِّصْنِى يَاربُّ خَلِّصْنِى يَاربُّ فإنَّ البَارَّ قَدْ فَنَى، وقَدْ قَلَّت الأمَانَةُ مِنْ بَنِى البَشَر. تَكَّلم كُلٌ أحَدٍ مَعَ قَريبهِ بالبَاطِلِ. شِفاهٌ غَاشَّةٌ فى قُلوبِهِمْ، وبقُلُوبِهِمْ تكَلَّمُوا. يَسْتأصِلُ الرَّبُّ جَمَيعَ الشِّفاهِ الغَاشَّةِ، واللِّسَانِ النَّاطِقِ بالكِبْريَاءِ، الذِينَ قالُوا نُعظِّمُ ألْسِنَتَنَا. شِفَاهُنا مَعَنا. فَمَن هُوَ يَسُوُد عَلْينا؟ مِنْ أجْل شَقَاءِ المسَاكِين وتَنهُّدِ البَائِسينَ الآنَ أقُومُ، يقُولُ الرَّبُّ، أصْنَعُ الَخَلاصَ عَلانيةً. كَلامُ الرَّبِّ كَلامٌ نَقىٌّ، كفِضَّةٍ مُصفَّاةٍ مُجرَّبةٍ فى الأرْض قَدْ صُفِّيتْ سَبْعةَ أضْعَافٍ. وأنْتَ يارَبُّ تُنَجِّينَا وتَحْفَظُنا مِنْ هَذا الجيل وإلى الدَّهْر. المنَافِقُونَ حَوْلَنا يَمْشُونَ مِثْلَ عَظَمَتِكَ. رَفَعْتَ بَنِى البَشَرِ. هَلِّلُيلويا. + +++",
  "12": "إلَى مَتَى يارَبُّ تَنْسانِى؟ إلَى مَتَى يارَبُّ تَنْسانِى؟ إلَى الإنْقِضَاءِ؟ حَتَّى مَتّى تَصْرفُ وَجْهَك عنِّى؟ إلَى مَتَى أُرَدِّد هَذِهِ المشُورَاتِ فى نَفْسِى، وهَذِهِ الأوْجَاعُ فى قَلْبى النّهَارَ كُلَّه؟ إلَى مَتَى يَرْتفِعُ عَدوِّى عَلىَّ؟ انْظُرْ واسْتَجِبْ إلىَّ يَاربِّى وإلَهِى. انَرْ عَيْنىَّ لِئلاَّ أنَامُ نَومَ الموْتِ، لِئلا يَقولَ عَدوِّى إنِّى قَدْ قَويتُ عَليْهِ. الذينَ يُحْزنُونَنِى يَتهلَّلُونَ إنْ أنَا زَلَلْتُ. أمَّا أنَا فَعَلىِ رَحْمتكَ توَكَّلتُ، يبْتَهجُ قَلبِى بَخَلاصِكَ. أُسبِّحُ الرَّبَّ الَمحْسِن إلىَّ، وأُرتِّل لاسْمِ الرَّبِّ العَالِى. هَلِّلُيلويا. + +++",
  "14": "يارَبَّ مَنْ يَسْكنُ فى مَسْكنِكَ يارَبَّ مَنْ يَسْكنُ فى مَسْكنِكَ، مَنْ يَحلُّ فى جَبَل قُدْسِكَ؟ السَّالِكُ بِلاعَيبٍ. والفَاعِلُ البِرَّ، والمتكَلِّمُ بالَحَقِّ فى قَلْبهِ، الذِى لا يَغشُّ بلِسَانهِ، ولا يَصْنعُ بقَريبِهِ سُوءاً، ولا يَقْبلُ عَاراً عَلى جِيرانِهِ. فاعِلُ الشَّرِّ مَرْذُولٌ أمَامَه، ويُمجِّدُ الذِين يتَّقُونَ الرَّبَّ. الذِى يَحْلفُ لِقَريبِهِ، ولايَغْدرُ بهِ. ولايُعْطِى فِضَّتَهُ بالرِّبَا، ولا يَقْبلُ الرَّشْوةَ عَلَى الأبْرِياء، الذِى يَصْنعُ هَذا لايَتَزعْزعُ إلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "15": "احْفَظْنِى يا رَبُّ احْفَظْنِى يا رَبُّ فإنِّى عَليْكَ تَوكَّلتُ. قُلتُ للرَّبِّ أنْتَ رَبِّىِ. ولا تَحْتاجُ إلى صَلاحِى. أظْهَرَ عَجائِبَهُ لِقدِّيسِيهِ الذِينَ فى أرْضِهِ، وصَنعَ فِيِهمْ كلَّ مِشيئاتِهِ. كَثُرتْ أمْراضُهُمْ الذِينَ أسْرَعوا وَراءَ إلهٍ آخَرَ، لا أشْتَركُ فى قَرابِينِهِم مِنَ الدِّماءِ، ولا أذْكرُ أسْمَاءَهُم بشَفَتىَّ، الرَّبُّ هُوَ نَصيبُ مِراثِى وكأسِي، أنْتَ الذِى تَردُّ إلىَّ مِيرَاثِى. حِبالُ التَّقْسِيمِ وقَعَتْ لِى فى أرْضٍ خِصْبَةٍ. وإنَّ مِيراثِى لَثَابتٌ لِى. أُبارِكُ الرَّبَّ الذِى أفْهَمنِى. وأيْضاً إلَى اللَّيلِ وعَظَتْنى كُلْيَتاىَ، تقدَّمتُ فرأيْتُ الرَّبَّ أمامِى فى كُلِّ حينٍ، لأنَّه عَنْ يَمينِى لِكْى لا أتَزَعْزعَ، مِنْ أجْل هَذا فَرِحَ قَلْبى وتَهلَّلَ لِسَانِى. جَسَدِى أيْضاً يسْكنُ عَلىِ الرَّجاءِ. لأنَّكَ لا تَتْركُ نَفْسى فى الجحِيمِ. ولا تَدَعُ قُدُّوسَكَ يَرَى فَساداً. قَدْ عَرَّفتْنِى سُبُل الحَياةِ. تَمْلأنِى فَرحاً أمامَ وجْهكَ. البَهجَةُ فى يَمينِكَ إلَى الإنْقِضاءِ. هَلِّلُيلويا. + +++",
  "18": "السَّموات تُحدِّثُ بِمَجْدِ الله السَّمواتُ تُحدِّثُ بِمَجْدِ الله. والفَلَكُ يُخْبرُ بعَمَلِ يَديْهِ. يَوم إلى يَوْمٍ يُبْدى قَولاً. ولَيل إلَى ليلٍ يُظْهِرُ عِلْماً. لا قولَ ولا كلامَ، الذِينَ لا تَسْمعُ أصْوَاتَهُم. فى كلِّ الأرْضِ خَرَجَ مَنْطقُهُم. وإلَى أقْصَى المسْكُونةِ بَلغتْ أقْوالُهُم. جَعَلَ فى الشَّمْسِ مِظلتَهُ. وهِىَ مِثلُ العَريسِ الخَارجِ مِنْ خِدْرهِ. يتَهلَّلُ مِثْل الجَبَّار الذِى يُسْرعُ فى طَريقِهِ. مِنْ أقْصَى السَّماءِ خُروجُها، ومُنْتهَاهَا إلَى أقْصَى السَّماءِ ولا شَئ يخْتَفى مِنَ حَرارَتْهَا. نَامُوسُ الرَّبِّ بِلاَ عَيبٍ، يَردُّ النُّفوسَ. شَهادَةُ الرَّبِّ صادِقَةٌ، تُعلِّمُ الأطْفال. فَرائِضَ الرَّبِّ مُسْتقِيمةٌ، تُفْرحُ القَلْب. وَصيَّةُ الرَّبِّ مُضيئةٌ، تُنَيرُ العَيْنيْنِ عَنْ بُعدٍ. خَشْيةُ الرَّبِّ زَكيَّةٌ، دَائمَةٌ إلَى أبَدِ الأبَدِ. أحْكامُ الرَّبِّ أحْكامُ حَقِّ وعادِلةٌ مَعاً. مَشِيئةُ قَلْبهِ مُخْتارَةٌ أفْضَلُ مِنَ الذَّهَبِ والحَجَرِ الكَثِيرِ الثَّمنِ، وأحْلَى مِنَ العَسَلِ والشَّهدِ. عَبْدكَ يَحْفظُها، وفى حِفْظهَا ثَوابٌ عَظِيمٌ. الهَفَواتُ مِنَ يَشْعرُ بِهَا؟ مِنَ الخَطايَا المسْتَتِرةُ يَاربُّ طهِّرِنى. ومِنَ المتكبِّرينَ احْفَظْ عَبْدَكَ، حَتَّى لا يَتسَلَّطوا عَلىَّ فَحينَئذٍ أكُونُ بِلا عَيبٍ، وأتَنقَّى مِنْ خَطيَّةٍ عَظِيمةٍ، وتَكونُ جَميعُ أقْوالِ فَمِى وفِكْرِ قَلبىِ مَرضِيَّةً أمَامَكَ فى كلِّ حينٍ. يَاربُّ أنتَ مُعيِنى ومُخلِّصِى. هَلِّلُيلويا. + +++",
  "19": "يَسْتَجيبُ لكَ الرَّبُّ (†) يَسْتَجيبُ لكَ الرَّبُّ فى يَومِ شِدَّتكَ، يَنْصُركَ إسْمُ إلَهِ يَعْقوبَ. يُرْسِلُ لَكَ عَوْناً مِنْ قُدْسِهِ، ومِنْ صهْيون يعضِّدَكَ، يَذْكُرُ جَميعَ ذَبائِحكَ، ويَستسمِنُ مُحْرقاتكَ. يُعْطيكَ الرَّبُّ حَسَبَ قَلْبكَ، ويُتمِّمُ كلَّ مَشورَتَكَ. نَعْترفُ لَكَ يا رَبُّ بخَلاصِكَ، وباسْمِ إلهِنا نَنْمو. يُكمِّلُ الرَّبُّ كلَّ سُؤْلكَ. الآنَ عَلمْتُ أنَّ الرَّبَّ قَدْ خَلَّصَ مَسيحَهُ، واسْتَجابَ لهُ مِنْ سَماءِ قُدْسِهِ بجَبَروتِ خَلاصِ يمينِهِ. هَؤُلاءِ بمَرْكباتٍ، وهَؤُلاءِ بخَيْلٍ. ونَحنُ باسْم الرَّبِّ إلَهِنا نَنْمو. هُمْ عَثَروا وسَقَطوا، ونَحْن قُمْنا وانْتَصَبْنا. يا رَبُّ خلِّصْ مَلِككَ واسْتَجِبْ لَنا يَوْمَ نَدْعوكَ. هَلِّلُيلويا. + +++",
  "22": "الرَّبُ يَرْعانى الرَّبُ يَرْعانى فَلا يُعْوزُنى شَئ فى مَراعٍ خُضْرٍ يُسْكِنُنى، إلَى مِياهِ الرّاحةِ يورِدُنى. يَردُّ نَفْسى. يَهْدينى إلَى سُبُلِ البرِّ مِنْ أجْلِ اسْمِهِ. إنْ سَلَكْتُ فى وَسَطِ ظِلالِ الموْتِ فَلا أخافُ شَرًّاً، لأنَّكَ أنْتَ مَعى، عَصاكَ وعُكّازكَ هُما يُعزِّيانَنى. هَيَّأتَ قُدّامى مائدةً تُجاهَ مُضايقىَّ. مَسَحتَ بالزَّيتِ رَأسى، وكَأْسُك رَوتْنى بِقوَّةٍ. ورَحْمتُكَ تُدْركنى جَميعَ أيّامِ حَياتى، ومَسْكَنى فى بَيتِ الربِّ إلَى مَدَى الأيَّامِ. هَلِّلُيلويا. + +++",
  "23": "للرَّبِّ الأرْضُ ومِلْؤُها للرَّبِّ الأرْضُ ومِلْؤُها، المسْكونَةُ وجَميعُ السّاكِنينَ فيها. لأنَّهُ عَلى البِحار أسَّسَها، وعَلَى الأنْهار هَيَّأها. مَنْ يَصْعَد إلَى جَبلِ الرَّبِّ، أوْ مَنْ يقومُ في مَوْضع قُدْسِهِ؟ الطّاهِرُ اليَدَيْن والنَّقىُّ القَلْبِ، الَّذى لَمْ يَحْمل نَفْسَه إلَى الباطِل ولَمْ يَحْلف بالغِشِّ، هَذا يَنالُ بَرَكةً مِنَ الرَّبِّ، ورَحْمةً مِنَ اللَّهِ مُخَلِّصهُ. هَذا هُوَ جيلُ الَّذينَ يَطلبونَ الرَّبَّ ويبْتَغونَ وَجْه إلهِ يَعْقوبَ. ارْفَعوا أيُّها الرُّؤساءُ أَبْوابَكُم، وارْتفعى أيَّتها الأبْوابُ الدَّهْريَّةُ فَيدْخُلُ مَلِكُ المجْدِ. مَنْ هُوَ هَذا مَلِكُ المجْدِ؟ الرَّبُّ العَزيزُ القَديرُ، الرَّبُّ القَّوِىُّ فى الحُروبِ. ارْفعوا أيُّها الرُّؤساءُ أبْوابَكمْ، وارْتَفعى أيَّتُها الأبْوابُ الدَّهْريَّةُ فَيدْخُلُ مَلِكُ المجْدِ. مَنْ هُوَ هَذا مَلِكُ المجْدِ؟ رَبُّ القُوّاتِ، هَذا هُوَ مَلِكُ المجْدِ. هَلِّلُيلويا. + +++",
  "24": "إلَيكَ يَارَبُّ رفَعْتُ نَفْسِى إلَيكَ يَارَبُّ رفَعْتُ نَفْسِى. يا إلهِى عَليْكَ تَوكَّلتُ. فَلاَ تُخْزنِى إلى الأبَدِ. ولا تُشْمِتْ بى أعْدائِى. لأنَّ جِميعَ الذِينَ ينْتظِرونَكَ لا يُخَزَونَ. ليُخْزَ الذِينَ يصْنَعونَ الإثْمَ باطِلاً. أظْهِرْ لى يَا ربُّ طُرقَكَ، وعلِّمْنى سُبُلَكَ. اهْدِنى إلى عَدلِكَ وعلِّمْنِى. لأنَّكَ أنتَ هُو اللهُ مُخلِّصِى. وإيَّاكّ انْتَظرتُ النَّهارَ كلَّهُ. أذْكُر يَا ربُّ رَأْفاتِكَ ومَراحِمَك، لأنَّهَا ثَابتَةٌ مُنذُ الأزلِ. خَطايَا شَبَابِى وجَهْلى لا تُذْكَر. كَرحْمتِك أذْكُرنِى أنْتَ منْ أجْلِ خَلاصكَ يَا ربُّ. الرَّبُّ صَالحِّ ومُسْتَقيمٌ، لِذلِكَ يُرشِدُ الذِينَ يُخْطئونَ فى الطَّريقِ. يَهْدى الوُدعَاءَ فى الحُكْمِ، يُعلِّمُ الوُدعَاءَ طُرقَهُ. جَميعُ طُرق الرَّبِّ رَحْمةٌ وحَقٌ لحَافِظِى عَهْدهِ وشَهَادَاتِه. مِنْ أجْلِ اسْمِكَ يا رَبُّ إغْفِر لى خَطيَّتِى لأنَّها كَثيرةٌ. مَنْ هُو الإنْسانُ الخَائفُ الرَّبِّ، يرْشِدهُ فى الطَّريقِ التِى إرْتَضَاهَا. نَفْسهُ فى الخَيْراتِ تثْبُتُ، ونَسْلهُ يَرثُ الأرْضَ. الرَّبِّ عزٌّ لخَائفِيهِ. وإسْمُ الرَّبِّ لأتْقيَائه. ولَهُم يُعْلنُ عَهدَه. عَيْناىَ تَنْظرَان إلى الرَّبِّ فى كلِّ حينٍ. لأنَّهُ يُخْرجُ مِنْ الفخِّ رِجْلَىَّ. انْظُرْ إلىَّ وارْحَمنِى. لأنِّى ابنٌ وَحِيدٌ وفَقِيرٌ أنَا. أحْزانُ قَلبِى قَدْ كثُرَتْ. اخْرِجْنِى مِنْ شَدائِدِى. انْظُر إلى ذُلِّى وتَعَبى. واغْفِرْ لى جَمِيعَ خَطايَاىَ. انْظُر إلى أعْدائِىِ فإنَّهمْ قَد كَثُرُوا وأبّغَضونِى ظلْماً. احْفَظْ نَفْسِى ونَجِّنِى، لا أخْزَى لأنِّى عَليكَ تَوكَّلتُ. الذِينَ لا شَرَّ فِيهمْ والمسْتَقيمُونَ لَصقُوا بى، لأنِّى انْتظَرْتَكَ يارَبُّ. يا اللَّهُ انْقذْ إسْرائِيلَ مِنْ جَمِيعِ شَدائِدِهِ. هَلِّلُيلويا. + +++",
  "25": "احْكُمْ لى يا ربُّ احْكُمْ لى يا ربُّ فإنّي بِدِعَتِى سَلَكتُ، وعَلَى الرَّبِّ تَوكَّلتُ فَلا أضْعُفْ. اخْتَبرْنى يا رَبُّ وجَرِّبْنى، نَقِّ قَلبى وكُلْيَتَىَّ لأنَّ رَحْمتَكَ أمامَ عَيْنى، وقَد ارْتضيْتُ بحَقِّكَ. لَمْ أجْلسْ فى مَجْلسِ شرّيرٍ، ومَعَ مُخالِفى النّاموس لَمْ أدْخُلْ. أبْغَضتُ مَجمعَ الأشْرارِ، ومَعَ المنافِقينَ لَمْ أجْلسْ. أغْسلُ يَدىَّ بالنَّقاوةِ، وأَطوف بِمذْبَحِكَ يا رَبُّ. لأسْمَعَ صَوتَ تَسْبيحِكَ، وأْنطقَ بجميعِ عَجائِبكَ. يا رَبُّ أحْبَبْتُ جَمالَ بَيْتِكَ، ومَوضِعَ مَسْكنِ مَجْدكَ فَلا تُهْلِك مَعَ المنافِقينَ نَفْسى، ولا مَعَ رِجالِ الدِّماءِ حَياتى. الَّذينَ فى أيْديهمُ الإثْمُ، ويَمينُهُمُ امْتَلأتْ رشْوَةً. أمّا أَنا فَبِدِعَتى سَلكْتُ. انْقِذْنى وارْحَمنى لأنَّ رِجْلى وقَفَت فى طَريقٍ مُسْتَقيمٍ. فى الجَماعاتِ أُبارِكُكَ يا رَبُّ. هَلِّلُيلويا. + +++",
  "26": "الرَّبُّ نُورِى وخَلاصِى الرَّبُّ نُورِى وخَلاصِى مِمَّن أخَافُ. الرَّبُّ نَاصِرُ حَياتِى مِمَّن أجْزَعُ. عِندَ اقْتِرابِ الأشْرارِ مِنِّى لِيأْكُلوا لحْمِى، مُضايقَىَّ وأعْدائِى عَثُروا وسَقَطُوا. إنْ يُحارِبَنِى جَيشٌ فلَنْ يَخافَ قَلْبى. إنْ قامَ علىَّ قِتالٌ فَفى هَذا أنَا أطَمْئنُّ. وَاحِدة سَألتُ مِنَ الرَّبِّ وإيَّاهَا ألْتمسُ. أنْ أسْكُنَ فى بَيتِ الرَّبِّ كلَّ أيَّامِ حَياتِى. لِكىْ أنْظرَ نَعيمَ الرَّبِّ، أتَفرَّسَ فى هَيْكلِه المقُدَّسِ. لأنَّهُ أخْفانِى فى خَيْمتِهِ، فى يَومِ شِدَّتِى، سَتَرنِى بسِتْرِ مِظلَّتهِ. وعَلَى صَخْرةٍ رفَعَنى. والآنَ هُوذَا قَدْ رَفَع رَأسِى عَلَى أعْدائِى. طُفْتُ وذَبَحْتُ فى مِظلَّتِه ذَبيحَةَ التَّهْليلِ. أسبِّحُ وأرتِّلُ للرَّبِّ. اسْتَمعْ يارَبُّ صَوْتِى الذِى بِهِ دَعوتُكَ. ارْحَمنِى واسْتَجبْ لى فإنَّهُ لكَ قالَ قلْبِى: طَلبْتُ وجْهَك، ووَجْهَك ياربُّ ألْتمِسُ. لا تَحْجبْ وجْهَك عنِّى ولا تُعْرضْ بغَضَبٍ عَن عَبْدكَ. كُنْ لى مُعيناُ. لا تخْذُلنِى ولا تَرْفضنِى يَا اللهُ مُخلِّصِى. فإنَّ أبِى وأُمِّى قَدْ ترَكانِى، وأمَّا الرَّبُّ فقبِلَنِى. علِّمْنىِ ياربُّ طّريقَكَ وأهْدِنى فى سَبِيلٍ مسْتَقيمٍ مِنْ أجل أعدائىِ. لا تسلمَنى إلى أيدى مُضايِقىَّ، لأنَّه قَدْ قامَ عَلىَّ شُهودُ زُورٍ. وكَذبُوا عَلىَّ ظُلماً. أنَا أؤمِنُ أنِّى أُعايِنُ خَيْرات الرَّبِّ فى أرْض الأحْياءِ. انْتظِرِ الرَّبَّ تَقوَّ وليتَشَدَّدْ قلْبكَ وانْتَظِر الرَّبَّ. هَلِّلُيلويا. + +++",
  "28": "قَدِّموا للرَّبِّ يا أبْناءَ اللَّهِ قَدِّموا للرَّبِّ يا أبْناءَ اللَّهِ. قَدِّموا للرَّبِّ أبْناءَ الكِباشِ. قَدِّموا للرَّبِّ مَجْدًا وكَرامَةً. قَدِّموا للرَّبِّ مَجْدًا لاسْمِهِ. اسْجُدوا للرَّبِّ فى دارِ قُدْسِهِ. صَوْتُ الرَّبِّ عَلَى المياهِ. إلَهُ المجْدِ أرْعَدَ. الرَّبُّ عَلَى المياهِ الكَثيرةِ. صَوْتُ الرَّبِّ بقُوَّةٍ. صَوْتُ الرَّبِّ بجَلالٍ عَظيمٍ. صَوْتُ الرَّبِّ يُحَطِّمُ الأرْز. الرَّبُّ يُكسِّرُ أرْز لُبْنانَ فتَقْفزُ مِثْل عِجْل لُبْنانَ وسِرْبون مِثْلَ إبْنِ البَقَر الوَحْشىِّ. صَوْتُ الرَّبِّ يُزَلْزلُ القَفْرَ. الرَّبُّ يُزَلْزلُ بَرِّيَّة قادِش. صَوْتُ الرَّبِّ يُولِّد الأيائِلَ ويُجرّد الغاباتِ. وفى هَيْكلِهِ المقَدَّسِ كُلُّ واحِدٍ ينْطِقُ بالمجْدِ. الرَّبُّ يَسْكنُ فى الطّوفانِ، الرَّبُّ يَجْلسُ. مَلِكاً إلَى الأبَدِ. الرَّبُّ يُعْطى شَعْبهُ قوَّةَ، الرَّبُّ يُبارِكُ شَعْبَه بالسَّلامِ. هَلِّلُيلويا. + +++",
  "29": "أعظِّمُكَ يا رَبُّ أعظِّمُكَ يا رَبُّ لأنَّكَ إحْتَضَنْتنى، ولَمْ تُشمِت بى أعْدائى. أيُّها الرَّبُّ إلَهي صَرخْتُ إليْكَ فَشفَيْتنى. يا رَبُّ أصْعَدتَ مِنَ الجَحيم نَفْسى، وخلَّصْتَنى مِنَ الهابِطينَ فى الجُبِّ. رَتِّلوا للرَّبِّ يا جَميعَ قِدّيسيهِ، واعْتَرفوا لذِكْرِ قَداسَتِه لأنَّ للحْظَة غَضَبَه، وحَيَاٌة فى رِضاه. فى العَشاءِ يَحلُّ البُكاءُ وفى الصَّباحِ السُّرورُ. أَنا قُلتُ فى طُمأْنينَتى لا أتَزعْزَعُ إلَى الدَّهْر، يا رَبُّ بمَسَرَّتكَ أعْطَيتَ بَهائى قُوَّةً. صَرفْتَ وجْهَكَ عَنّى فَصِرْتُ قَلِقًا.إليْكَ يا رَبُّ أصْرُخُ، وإلَى إلَهى أتَضرَّعُ. أيَّةُ منْفَعةِ مِنْ دَمى إذا هَبَطتُ إلَى الجَحيمِ، هَلْ يَعْترِفُ لَكَ التُّرابُ أوْ يُخْبرُ بحقِّكَ. سَمعَ الرَّبُّ فَرحِمَنى، الرَّبُّ صارَ لى عَوْناً، حَوَّلتَ نَوْحى إلَى فَرَحٍ لى، مزَّقْتَ مِسْحى ومَنْطَقْتنى سُروراً لِكىْ تُرَتل لَكَ نَفْسى ولا يَحْزَنُ قَلْبى. أيُّها الرَّبُّ إلَهى إلَى الأبَدِ أعْتَرفُ لَكَ. هَلِّلُيلويا. + +++",
  "33": "أُباركُ الرَّبَّ فى كُلِّ وَقْتٍ أُبَارِكُ الرَّبَّ فى كُلِّ وَقْتٍ، وفى كُلِّ حينٍ تَسْبحَتُهُ فى فَمى، بالرَّبِّ تَفْتَخرُ نَفْسى، يَسْمعُ الوُدَعاءُ ويفْرَحونَ عَظِّموا الرَّبَّ مَعى لنَرْفَع إسْمَهُ جَميعاً، طلَبْتُ إلَى الرَّبِّ فاسْتَجابَ لى، ومِنْ جَميعِ مَخاوِفى نَجّانى تَقدَّموا إلَيْهِ واسْتَنيروا، ووُجوهكُمْ لا تَخْزَى، هَذا المسْكينُ صَرَخَ فاسْتَمعَهُ الرَّبُّ ومِنْ جَميعِ ضيقاتِه خَلَّصَهُ. يُعَسْكِرُ مَلاكُ الرَّبِّ حَوْلَ كُلِّ خائِفيه ويُنَجّيهِم. ذوقوا وانْظُروا ما أطْيَبَ الرَّبَّ، طوبَى للإنْسانِ المتَّكِلِ عَليْهِ. اتَّقوا الرَّبَّ يا جَميعَ قِدّيسيهِ، فإنَّ الَّذينَ يتَّقونهُ لا يَعوزهُمْ شَئٌ، الأشْبالُ إحْتاجتْ وجاعَتْ أمّا الَّذينَ يبْتَغونَ الرَّبَّ فَلا يَعوزهُمْ أىُّ خَيرٍ. هَلُمَّ أيُّها البَنونَ اسْتَمعوا لى، فأُعلِّمكُمْ مخافَة الرَّبِّ. مَنْ هُوَ الإنْسانُ الَّذى يَهْوَى الحَياةَ، ويُحبُّ أَنْ يَرَى أيّاماً صالِحَةً؟ صُنْ لِسانَكَ عَنِ الشَّرِّ وشَفَتَيْكَ عَنِ النُّطْقِ بالغِشِّ، حِدْ عَنِ الشَّرِّ واصْنَع الخَيْرَ، اطْلُب السَّلامَةَ واتَّبِعْها فإنَّ عَيْنَى الرَّبِّ عَلَى الصِّدّيقينَ، وأذُنَيْهِ مُصْغيَتانِ إلَى طلبَتِهِمْ. وجْهُ الرَّبِّ ضِدَّ صانِعى الشَّرِّ ليَمْحو مِنَ الأرْضِ ذِكْرَهُم. الصِّدّيقونَ صَرَخوا والرَّبُّ اسْتَجابَ لَهُم، ومِنْ جَميعِ شَدائِدِهمْ نَجّاهُمْ. قَريبٌ هُوَ الرَّبُّ مِنْ مُنْسَحِقى القَلْب، ويُخلِّصُ المتَواضِعينَ بالرّوحِ.كَثيرةٌ هِىَ أحْزانُ الصِّدّيقينَ ومِنْ جَميعِها يُنجّيهمُ الرَّبُّ. يَحْفظُ الرَّبُّ جَميعَ عِظامِهِم وواحِدةٌ مِنْها لا تَنْكسِرُ. يَموتُ الخُطاةُ بشَرِّهم، ومُبْغضو الصِّدّيقِ يَنْدمونَ. الرَّبُّ يَفْدى نُفوسَ عَبيدهِ، ولا يَنْدمُ جَميعُ المتَّكلينَ عَليْه. هَلِّلُيلويا. + +++",
  "40": "طوبَى لِمَنْ يَتعَطَّفُ عَلَى المسْكينِ طوبَى لِمَنْ يَتعَطَّفُ عَلَى المسْكينِ، فى يَومِ الشَّرِّ يُنَجّيهِ الرَّبُّ. الرَّبُّ يَحْفظُهُ ويُحَيّيهِ ويَجْعَلهُ فى الأرْضِ مَغْبوطاً. ولا يُسلِّمهُ لأيْدى أعْدائِهِ. الرَّبُّ يُعينُهُ عَلَى سَرير وَجَعِهِ، إنَّكَ أقَمْتَه مِنْ كُلِّ أوْجاعِ مَرَضِهِ. أَنا قُلْتُ يا رَبُّ إرْحَمْنى، إشْفِ نَفْسى لأنّى قَدْ أخْطأتُ إلَيكَ. أعْدائى تَقوَّلوا عَلَىَّ شَرًّا: مَتَى يَموتُ ويُبادُ اسْمُه؟ الَّذي دَخَل لِيراني كانَ يتَكلَّمُ بالرِّياءِ، وقَلبُهُ يُضْمرُ لهُ شَرَّا، ثمَّ كانَ يخْرُجُ خارجاً ويَتكلَّمُ عَلىَّ. تَهامَسَ عَلىَّ جَميعُ أعْدائى وتَشاوَروا عَلىَّ بالسّوءِ، وكَلاماً مُخالِفاً للنّاموس رَتَّبوا عَلىَّ، قالوا: ألا يَعود الرّاقِدُ أنْ يَقوم؟ حتَّى الإنْسانُ المسالِمُ الَّذى وَثقْتُ بهِ الَّذى أكَلَ خُبْزى رَفَعَ عَلىَّ عَقِبَهُ. وأنْتَ يا رَبُّ ارْحَمْنى وأقمْنى فأُجازيهم. بهَذا عَلمْتُ أنَّك هَويتَنى، لأنَّ عَدوّى لَنْ يُسرّ بى. أمّا أنا فَمِنْ أجْلِ دَعَتى قَبلْتَنى وثَبتنى أَمامك إلَى الأبَدِ. مُبارَكٌ الرَّبُّ إلهُ إسْرائيل، مِن الأزَل وإلَى الأبَدِ آمين. هَلِّلُيلويا. + +++",
  "42": "احْكُمْ لى يا رَبُّ احْكُمْ لى يا رَبُّ وانْتقِمْ لمظْلمتى، مِنْ امَّةٍ غَيرِ بارَّةٍ ومِنْ إنْسانٍ ظالمٍ وغاشٍّ نَجِّنى. لأنَّكَ أنْتَ هُوَ إلَهى وقُوَّتى، لماذا أقْصَيْتنى؟ ولِماذا أسْلكُ كَئيباً مِنْ مُضايَقةِ عَدُوّى؟ أَرْسِلْ نورَكَ وحَقَّكَ فإنَّهما يَهْدِيانَنى ويُصْعِدانَنى إلَى جَبَلكَ المقَدَّسِ وإلَى مَسْكنِكَ، فأدْخلُ إلَى مَذْبحِ اللَّهِ تِجاهَ وَجْه اللَّهِ الَّذى يُفرحُ شَبابى. أعْتَرفُ لَكَ بالقيثارةِ يا اللَّهُ إلَهى. لِماذا أنْتِ حَزينَةٌ يا نَفْسى ولِماذا تُزْعِجينَنى؟ تَوكَّلى عَلَى اللَّهِ فإنِّى أعْترفُ لهُ، خَلاص وَجْهى هُوَ إلَهى. هَلِّلُيلويا. + +++",
  "44": "فاضَ قَلْبى فاضَ قَلْبى بِكلامٍ صالحٍ. إنّى أُخْبرُ الملكَ بأفْعالى، لِسانى قَلمٌ كاتِبٌ ماهِرٌ. إنَّك أبْرعُ جَمالاً مِنْ بَنى البَشَرِ. وقَد انْسكَبتِ النِّعْمةُ عَلَى شَفَتيْكَ، فَلذَلكَ بارَكَكَ اللَّهُ إلَى الدَّهْرِ. تَقلَّدْ سَيْفكَ عَلَى فَخذِكَ أيُّها القَوىُّ بجلالِكَ وجَمالِكَ، اسْتَله وانْجَحْ وامْلُكْ. مِنْ أجْلِ الحَقِّ والدَّعةِ والعَدْلِ، وتَهْديكَ بالعَجَبِ يَمينُكَ. نبْلُكَ مَسْنونَةٌ فى قَلْب أعْداءِ الملِكِ أيُّها الجَبّارُ، الشُّعوبُ تَحْتكَ يسْقُطونَ. كرسِيُّكَ يا اللَّهُ إلَى دَهْرِ الدُّهورِ، قَضيبُ الاسْتِقامَةِ هُوَ قَضيبُ مُلْككَ لأنَّكَ أحْبَبْتَ البِّرَ وأبْغَضْتَ الإثْمَ، مِنْ أجْلِ هَذا مَسَحكَ اللَّهُ إلَهكَ بزَيْتِ البَهجةِ أفْضَلَ مِنْ رُفقائِكَ، المرُّ والميعَةُ والسَّليخَةُ مِنْ ثِيابكَ، مِنْ قُصورِ العاجِ الَّتى أبْهَجتْكَ. بَناتُ المُلوكِ فى تَكْريمِكَ. قامَت الملِكةُ عَنْ يَمينِكَ بِثَوْبٍ موشَّى بالذَّهَبِ، مُزَيَّنةٌ بأنْواعٍ كَثيرةٍ. اسْمَعى يا إبْنَتى وانْظُرى وأَميلى أُذُنَكِ، وانْسَىْ شَعْبكِ وبَيْتَ أبيكِ فإنَّ الملِكَ قَد اشْتَهَى حُسْنَكِ، لأنَّهُ هُوَ ربُّكِ ولَهُ تَسْجُدينَ. ولَهُ تَسْجُد بَناتُ صورٍ بالهَدايا، ويَتَرجَّى وجْهَهُ أغْنياءُ شَعْبِ الأرْضِ. كُلُّ مَجْد إبْنَةُ الملِكِ مِنْ داخِل. مشْتمِلةٌ بأطرافٍ مُوَشّاةٍ بالذَّهَبِ، مُزَيَّنَةٍ بأشْكالٍ كَثيرةٍ. تَدْخلُ إلَى الملِكِ عَذارَى فى إثْرها، جَميعُ قَريباتِها إليْهِ يُقَدَّمنَ. يَبْلغنَ بفَرحٍ وابْتِهاجٍ، يدْخُلنَ إلَى هَيْكلِ الملِكِ ويَكونُ لَكَ أْبناء عِوَضاً مِنْ أبائِكَ، تُقيمهُم رُؤساءَ عَلَى سائِرِ الأرْضِ، ويَذْكُرونَ إسْمَكَ جيلاً بَعْد جيلٍ، مِنْ أجْل ذَلكَ تَعْترفُ لَكَ الشُّعوبُ يا اللَّهُ إلَى الدَّهْرِ وإلَى دَهْرِ الدُّهورِ. هَلِّلُيلويا. + +++",
  "45": "إلَهُنا مَلجَأُنا وقُّوَّتنا إلَهُنا مَلجَأُنا وقُّوَّتنا ، ومُعينُنا فى شَدائدِنا الَّتى أصابتْنا جداً، لِذَلكَ لا نَخْشَى إذا تزَعْزَعتِ الأرْضُ وانْقَلبَتِ الجِبالُ إلَى قَلبِ البحارِ. تعُجُّ المياهُ وتَجيشُ. تَتَزعْزَعُ الجِبالُ بعِزَّتهِ. مَجارى الأنْهارِ تُفَرِّحُ مَدينَةَ اللَّهِ. لقَد قَدَّس العَلىُّ مَسْكنَهُ، واللَّهُ فى وَسَطها فَلَن تَتَزَعْزع. يُعينُ اللَّهُ وَجْهَها. إضْطَربَتِ الأُممُ، وماجَتِ الممالِكُ، أبْدَى صَوْتَه فَتَزلْزَلت الأرْضُ. إلهُ القُوَاتِ مَعَنا ناصِرُنا هُوَ إلهُ يَعْقوبَ. هَلُمَّ فانْظُروا أعْمالَ الرَّبِّ الَّتى جَعَلها آياتٍ عَلَى الأرْضِ. الَّذى يَنْزعُ الحُروبَ إلَى أَقاصى الأرْضِ، يَسْحقُ قِسِيَّهُمْ ويَكْسِرُ سِلاحَهُم، ويَحْرقُ أتْراسَهُم بالنّارِ، تأمَّلوا واعْلَموا أنّى أَنا هُوَ اللَّهُ، أرْتَفِعُ بَينَ الأمَمِ وأتَعالَى فى الأرْضِ. الرَّبُّ إلهُ القُوّات مَعَنا، ناصِرُنا هُوَ إلَهُ يَعْقوبَ. هَلِّلُيلويا. + +++",
  "46": "يا جَميعَ الأُمَمِ صَفِّقوا بَأيْديكُم (†) يا جَميعَ الأُمَمِ صَفِّقوا بَأيْديكُم، هَلِّلوا لِلهِ بصَوْتِ الابْتِهاجِ. لأنَّ الرَّبَّ عالٍ ومرْهوبٌ، مَلِكٌ كَبيرٌ عَلَى كافَّةِ الأرْضِ. أخْضَعَ الشُّعوبَ لَنا. والأمَمَ تَحْتَ أقْدامِنا. اخْتارنا ميراثاً لَهُ، جَمالُ يَعْقوبَ الَّذى أُحبُّه. صَعِدَ اللَّهُ بتَهْليلٍ والرَّبُّ بصَوْتِ البوقِ، رَتِّلوا لإلَهنا رَتِّلوا، رَتِّلوا لمَليكِنا رَتِّلوا. لأنَّ الرَّبَّ هُوَ مَلِكُ الأرْضِ كلِّها، رَتِّلوا بفَهْمٍ. فإنَّ الرَّبَّ مَلكٌ عَلَى جَميعِ الأمَمِ، اللهُ جَلسَ عَلَى كُرْسيِّه المقَدَّسِ. رُؤَساءُ الشُّعوبِ إجْتَمعوا مَعَ إلهِ إبْراهيمَ، لأنَّ أعِزّاء اللَّهِ قَد ارْتَفعوا فى الأرْضِ جداً. هَلِّلُيلويا. + +++",
  "53": "اللَّهُمَّ بإسْمِكَ خَلِّصْنى (†) اللَّهُمَّ بإسْمِكَ خَلِّصْنى، وبقُوَّتكَ احْكُمْ لى. اسْتَمِعْ يا اللهُ صَلاتى، وأنْصِتْ إلَى كَلامِ فَمى. فإنَّ الغُرَباءَ قَدْ قاموا عَلَىَّ والأقْوياءَ طَلبوا نَفْسى، لَمْ يَجْعلوا اللَّه أمامَهُم. هُوَذا اللَّهُ عَوْنى والرَّبُّ ناصرُ نَفْسى، يَردُّ الشُّرورَ عَلَى أعْدائى وبِحَقِّكَ إسْتَأصِلهُم فأذْبَحُ لَكَ طائعاً، وأعْتَرفُ لإسْمِكَ يا رَبُّ فإنَّهُ صالِحٌ لأنَّكَ مِنْ جَميعِ الشَّدائِدِ نَجَّيْتنى وبأَعْدائى نَظَرتْ عَيْناىَ. هَلِّلُيلويا. + +++",
  "56": "ارْحَمْنى يا اللَّهُ ارْحَمْنى ارْحَمْنى يا اللَّهُ ارْحَمْنى، فإنَّهُ عَليْكَ تَوكَّلَتْ نَفْسى. وبظِلِّ جَناحَيْك أعْتَصِمُ، إلَى أنْ يَعْبُرَ الإثمُ. أصْرُخُ إلَى اللَّهِ العَلىِّ، الإلَه المحسِن إلَىَّ. أرْسَل مِنَ السَّماءِ فَخلَّصنى، وجَعَلَ العارَ عَلَى الَّذينَ يَطأُونَنى. أرْسَلَ اللَّهُ رَحْمَتَهُ وحقَّهُ، وخَلَّصَ نَفْسى مِنْ بَينِ الأشْبالِ إذْ نِمْتُ مُضْطَرباً. أسْنانُ أبْناءِ البَشَرِ سِلاحٌ وسِهامٌ، ولسانُهُم سَيْفٌ مُرهَفٌ اللَّهمَّ إرْتَفِعْ عَلَى السَّمَواتِ، وليرْتَفِعْ مَجْدُكَ عَلَى كُلِّ الأرْضِ. نَصَبوا لِرجْلى فِخاخاً وأحْنَوْا نَفْسى، حَفروا قُدّامَ وجْهى حُفْرةً سَقَطوا فيها. مُستَعدٌ قَلْبى يا اللَّهُ، مُسْتَعدٌ قَلْبى، أُسبِّحُ وأُرتِّلُ فى تَمْجيدى اسْتَيقِظى يا نَفْسى اسْتَيقِظْ أيُّها المزْمارُ والقيثارَةُ. أَنا أسْتَيقِظُ مُبَكِّرًا. أعْتَرفُ لَكَ فى الشُّعوبِ يا رَبُّ، وأرتِّلُ لَكَ فى الأمَمِ. لأنَّ رحْمتَكَ قَدْ عَظُمَت إلَى السَّمَواتِ وإلَى السَّحابِ عَدْلكَ. اللهُمَّ ارْتَفعْ عَلَى السَّمَواتِ ولْيرتَفِعْ مَجْدُك عَلَى سائِرِ الأرْضِ. هَلِّلُيلويا. + +++",
  "60": "اسْتَمعْ يا اللَّهُ طلبَتى اسْتَمعْ يا اللَّهُ طلبَتى، واصْغ إلَى صَلاتى. مِنْ أَقاصى الأرْضِ صَرَخْتُ إليْكَ عنْدَما ضَجرَ قَلْبى، عَلَى الصَّخْرةِ رَفَعْتنى وأرْشَدْتَنى. صِرْتَ رَجائى وبُرْجاً حَصيناً فى وَجْه العَدوِّ. فأسْكُن فى مَسْكنِكَ إلَى الدَّهْر، وأسْتظِل بسِتْرِ جَناحَيكَ. لأنَّكَ أنْتَ يا اللَّهُ اسْتَمَعتَ صَلَواتى، أَعْطَيْتَ ميراثاً لخائِفى إسْمِكَ، تَزيدُ الملِكَ أيّاماً عَلَى أيّامِهِ وسِنيناً عَلَى سِنيهِ. إلَى جيلٍ فَجيلٍ ويَدومُ إلَى الأبَدِ قُدّامَ اللَّهِ. رَحْمتُهُ وحَقُّه مَنْ يَبْتَغيهُمَا. هَكَذا أُرتِّلُ لإسْمِكَ إلَى دَهْرِ الدُّهورِ، لأَفى نُذورى يَوماً فَيَوماً. هَلِّلُيلويا. + +++",
  "62": "يا اللَّهُ إلَهي إليْكَ أُبَكِّرُ يا اللَّهُ إلَهي إليْكَ أُبَكِّرُ، إذْ عَطِشَتْ إليْكَ نَفسى يَشْتاقُ إلَيْكَ جَسَدى، فى أرْضٍ مُقْفرَةٍ ومَوْضِعٍ غَيرِ مَسْلوكٍ ومَكانٍ بَلا ماءٍ. هَكذا تَراءَيْتُ لَكَ فى القُدسِ، لأرَى قُوَّتَكَ ومَجْدَكَ، لأنَّ رحْمتَكَ أفْضَلُ مِنَ الحَياةِ. شَفَتاى تُسبِّحانك. لِذَلكَ أُبارِككَ فى حَياتى، وباسْمِكَ أرْفَعُ يَدى فَتشْبعُ نَفْسى كَما مِنْ شَحْمٍ ودَسَمٍ، بشِفاهِ الإبْتِهاجِ نُبارِكُ إسْمَك. كنْتُ أذْكُركَ عَلَى فِراشى، وفى أوْقات الأسْحارِ كنْتُ أُرتِّلُ لَكَ. لأنَّكَ صِرْتَ لى عَوْناً، وبظِلِّ جَناحيْكَ أبْتَهجُ. إلْتَصقَت نَفْسى بِكَ، ويَمينُكَ عَضَّدتْنى، أمّا الَّذينَ طَلَبوا نَفْسى للهَلاكِ، فيَدْخلونَ فى أسافِل الأرْضِ ويُدْفَعونَ إلَى يَدِ السَّيفِ، ويَكونونَ أنْصِبةً للثعالِبِ أمّا الملِكُ فَيفرحُ باللَّهِ، ويفْتَخرُ كُلُّ مَنْ يَحْلفُ بهِ. لأنَّ أفواهَ المتَكلَّمينَ بالظُّلْم تُسدُّ. هَلِّلُيلويا. + +++",
  "66": "لِيتَراءفَ اللَّهُ عَلينَا لِيتَراءفَ اللَّهُ عَلينَا ولِيُباركِنَا، وليُنِرْ بوجْهِهِ عَليْنَا ويَرْحَمْنا. لَتُعْرفَ فى الأرْض طَريقُكَ، وفى جَميعِ الأممِ خَلاصُكَ. فلْتَعْتَرَفْ لكَ الشَّعوبُ يا اللَّهُ، فلْتَعْترفْ لكَ الشُّعوبُ كلُّها. لتَفْرَح الأمَمُ وتَبْتهجُ، لأنَّكَ تدِينُ الشَّعوبَ بالإسْتِقامَةِ وتَهْدى الأممَ فى الأرْض. فلْتَعْتَرفْ لَكَ الشُّعوبُ يَا اللَّهُ، فلْتَعْتَرفْ لَكَ الشُّعوبُ جَميعاً الأرْضُ أعْطَتْ ثَمَرتَها. فَليُبارِكنَا اللهُ إلهنَا. لِيُباركنَا اللهُ. فَلْتَخشَهُ جَميعُ أقْطارِ الأرْضِ. هَلِّلُيلويا. + +++",
  "69": "اللَّهُمَّ إلْتَفتْ إلى مَعُونَتِى اللَّهُمَّ الْتَفتْ إلى مَعُونَتِى، يَاربُّ اسْرعْ واعِنِّى. ليُخْزَ ويَخْجَل طَالبُو نَفْسى، وليرْتَدَّ إلى خَلْفٍ ويَخْجَل الذِينَ يبْتَغونَ لى الشَّرَّ. وليرْجعَ بالخِزْىِ سَريعاً القَائِلونَ لى نَعِمَّاً نَعِمَّا. ولِيبْتَهجْ ويَفْرَح بكَ جَميعُ الذِينَ يلْتمسُونِكَ، ولِيَقَل فى كلِّ حينٍ مُحبُّو خَلاصِكَ لِيتعَظَّمَ الرَّبُّ. وأمَّا أنَا فمِسْكينٌ وفَقِيرٌ. اللَّهمَّ اعِنِّى. أنْتَ مُعينِى ومُخلِّصِى يَاربُّ فَلا تُبْطِئ. هَلِّلُيلويا. + +++",
  "83": "مَساكِنُكَ مَحْبوبةٌ مَساكِنُكَ مَحْبوبةٌ يا رَبُّ إلَهَ القُوّات. تَشْتاقُ وتَذوبُ نَفْسى للدُّخولِ إلَى دِيارِ الرَّبِّ. قَلْبى وجِسْمى قَد إبْتَهَجا بالإلَهِ الحَىِّ. العُصْفورُ وجَدَ لهُ بَيْتاً واليَمامَةُ عُشّاً لِتضَعَ فيهِ أفْراخَها، مَذابِحُكَ يا رَبُّ إلَه القُوّاتِ مَلِكى وإلَهى. طوبَى لِكلِّ السُّكانِ فى بَيْتِكَ، يُبارِكونَكَ إلَى الأبَدِ. طوبَى للرَّجُلِ الَّذى نُصرَتُهُ مِنْ عِنْدكَ يا رَبُّ، رَتَّبْ فى قَلبهِ أنْ يَصْعدَ، فى وادى البُكاءِ فى المَكانِ الَّذى قَرَّرهُ. لأنَّ البَرَكات يُعْطيها واضِعُ النّاموسِ، يَسيرونَ مِنْ قُوَّةٍ إلَى قُوَّةٍ. يَتَجلَّى إلهُ الآلِهَة فى صهْيونِ. أيُّها الرَّبُّ إلَه القُوّاتِ اسْمَعْ صَلاتى، انْصتْ يا إلهَ يَعْقوبَ. انْظُر أيُّها الإلهُ ناصِرُنا واطَّلِعْ إلَى وَجْهِ مَسيحكَ. لأنَّ يَوماً صالِحاً فى دِيارِكَ خَيرٌ مِنْ آلافٍ. اخْتَرتُ لنَفْسى أنْ أُطْرَحَ عَلَي بابِ بَيْتِ اللَّهِ أفْضَل مِنْ أنْ أسْكُنَ فى مَظال الخُطاةِ. لأنَّ الرَّبَّ الإلَهَ يُحبُّ الرَّحْمَة والحَقَّ، ويُعْطى مَجْداً ونِعْمةً. الرَّبُّ لا يَمْنَع الخَيْرات عَنِ السّالِكينَ بالدَّعَةِ. يا رَبَّ إلَه القُوّاتِ طوبَى للإنْسانِ المتَّكِلِ عَليْكَ. هَلِّلُيلويا. + +++",
  "84": "رَضِيتَ يا رَبُّ عَلَى أرْضِكَ (†) رَضِيتَ يا رَبُّ عَلَى أرْضِكَ، رَدَدْتَ سَبْى يَعْقوبَ، غَفَرتَ آثامَ شَعْبكَ، سَتَرتَ جَميعَ خَطاياهُم. حَللْتَ كُلَّ رِجْزكَ، رَجَعْتَ عَنْ سُخْط غَضَبِكَ. رُدَّنا يا إلَه خَلاصِنا، واصْرِفْ غَضَبِكَ عَنا، هَلْ إلَى الأبَدِ تَغْضبُ عَليْنا، أوْ تُواصِلُ رِجْزَكَ مِنْ جيلٍ إلَى جيلٍ؟ أنْتَ يا اللَّهُ تَعودُ فَتُحْيينا، وشَعْبُكَ يفْرَحُ بِكَ. أرِنا يا رَبُّ رَحْمَتَك واعْطِنا خَلاصَكَ. إنّى أسْمَعُ ما يَتَكلَّمُ بهِ الرَّبًّ الإلَهُ لأنَّهُ يتَكلَّمَ بالسَّلامِ لشَعْبهِ ولقدّيسيهِ وللَّذينَ رَجعوا إلَيْه بكُلِّ قلوبِهِمْ. لأنَّ خَلاصَهُ قَريبٌ مِنْ جَميعِ خائِفيه لِيسْكُن المجْدُ فى أرْضِنا. الرَّحْمةُ والحَقَّ تَلاقيا، البرُّ والسَّلامُ تلائَما، الحَقُّ مِنَ الأرْضِ أشْرَقَ، والبرُّ مِنَ السَّماءِ اطَّلعَ. لأنَّ الرَّبَّ يُعْطى الخَيْرات. وأرْضُنا تُعْطى ثَمرَها. البرُّ أمامهُ يسْلك، ويَسيرُ فى طَريقِ خطواتِهِ. هَلِّلُيلويا. + +++",
  "85": "اَمِلْ يا رَبُّ أُذُنَك اَمِلْ يا رَبُّ أُذُنَك واسْتَمعْنى لأنّى مسْكينٌ وبائِسٌ أَنا. احْفَظْ نَفْسي لأنّى بارٌّ، يا إلَهى خلِّصْ عَبْدَكَ المتَّكلُ عَليكَ. ارْحَمْنى يا رَبُّ لأنّى إليكَ أصْرخُ اليَومَ كلَّهُ. فَرِّحْ نَفْسَ عَبْدكَ لأنّى إليْكَ يا رَبُّ رَفَعتُ نَفْسى. لأنَّكَ أنْتَ يا رَبُّ صالِحٌ وَوَديعٌ، ورَحْمتُكَ كَثيرَةٌ لِكافَةِ المسْتَغيثينَ بكَ. انْصِتْ يا رَبُّ إلَى صَلاتى، واصْغِ إلَى صَوْتِ تَضرُّعى. فى يَومِ شدَّتى إليْكَ صَرَخْتُ فَأجَبْتنى. فَليسَ لَكَ شَبيهٌ فى الآلِهَةِ يا رَبُّ ولا مَنْ يَصْنَعُ كأعْمالِكَ. كُلُّ الأممِ الَّذينَ خَلقْتَهُم يَأْتونَ ويَسْجُدونَ أمامَكَ يا رَبُّ ويُمجِّدونَ اسْمَكَ. لأنَّكَ أنْتَ عَظيمٌ وصانِعُ العَجائِبِ، أنْتَ وحْدَكَ الإلَهُ العَظيمُ. اهْدِنى يا رَبُّ إلَى طَريقِكَ فَأسْلكَ فى حقِّكَ، ليَفْرحَ قَلبى عِنْد خَوفِه مِنْ اسْمِكَ. أعْتَرفُ لَكَ أيُّها الرَّبُّ إلَهى مِنْ كُلِّ قَلْبى، وأُمجِّدُ اسْمَكَ إلَى الأبدِ. لأنَّ رَحْمتَكَ عَظيمَةٌ عَلَىَّ، وقَدْ نَجَّيتَ نَفْسى مِنَ الجَحيمِ السُّفلىِّ. اللَّهُمَّ إنَّ مُخالِفى النّاموسِ قَدْ قاموا عَلَىَّ، ومَجْمعُ الأعِزّاءِ طَلبوا نَفْسى، ولَمْ يَسْبقوا أنْ يَجْعَلوكَ أمامهمْ، وأنْتَ أيُّها الرَّبُّ الإلهُ أنْتَ رَؤوفٌ ورَحيمٌ، أنْتَ طَويلُ الرّوحِ وكَثيرُ الرَّحْمةِ وصادِقٌ. انْظُر إلَىَّ وارْحَمْنى. اَعْطِ عِزَّةً لِعبْدِكَ، وخَلِّص ابْنِ أمَتكَ، اصْنَع مَعى آيةً صالحَةً لِيرَى ذَلكَ مُبْغِضىَّ فَيخْزوْا. لأنَّكَ أنْتَ يا رَبُّ أعنْتَنى وعزَّيتَنى. هَلِّلُيلويا. + +++",
  "86": "أَساساتُهُ فى الجِبالِ المقَدَّسةِ أَساساتُهُ فى الجِبالِ المقَدَّسةِ. يُحِبُّ الرَّبُّ أبْوابَ صِهْيونَ، أفْضَلُ مِنْ جَميعِ مَساكنِ يَعْقوبَ. أعْمالٌ مَجيدةٌ قَدْ قيلَتْ عَنْكِ يا مدينَةَ اللَّهِ. أذْكُرُ رَهَبَ وبابِلَ اللَّتَيْنِ تَعْرفانى هُوذا القَبائِلُ الغَريبةُ وصورُ وشَعْبُ الحَبشَةِ، هَؤُلاء وُلِدوا هُناكَ. أمّا صِهْيون الأمّ فتَقولُ: إنَّ إنْساناً وإنْساناً وُلِدَ فيها، وهُوَ العَلىُّ الَّذى أسَّسَها إلَى الأبَد. الرَّبُّ يُحَدِّث فى كُتُب الشُّعوبِ والرُّؤَساءِ، أُولَئِكَ الَّذينَ وُلِدوا فيها. لأنَّ سُكْنى الفَرِحينَ جَميعُهُم فيك. هَلِّلُيلويا. + +++",
  "90": "السّاكِنُ فى عَوْنِ العَلىِّ السّاكِنُ فى عَوْنِ العَلىِّ، يَسْتَريحُ فى ظِلِّ إلهِ السَّماءِ. يَقولُ للرَّبِّ أنْتَ هُوَ ناصِرى ومَلْجَأى، إلَهى فأتَّكِلُ عَليهِ. لأنَّهُ يُنجّيكَ مِنْ فَخِّ الصَّيّادِ، ومِنَ الوَباءِ الخَطِرِ. فى وَسَطِ مَنْكبيْهِ يُظلِّلُكَ، وتَحْتَ جَناحَيهِ تَعْتَصمُ، عَدْلهُ يُحيطُ بِكَ كالسِّلاح. فَلا تَخْشَى مِنْ خَوْفِ اللَّيْلِ ولا مِنْ سَهْمٍ يَطيرُ في النَّهار، ولا مِنْ أمْرٍ يسْلكُ في الظُّلمَةِ، ولا مِنْ سَقطَةِ وشَيْطانِ الظَّهيرَةِ. يَسْقطُ عَنْ يَساركَ أُلوفٌ وعَنْ يَمينكَ رِبْواتٌ، وأمّا أنْتَ فَلا يقْتَربُونَ إليْكَ، بَلْ بِعَيْنيْكَ تُعايِنُ ومُجازاةُ الخُطاةِ تُبْصرُ. لأنَّكَ أنْتَ يا رَبُّ رَجائى، جَعلْتَ العَلىَّ مَلْجأَكَ فلا تُصيبكَ الشُّرورُ، ولا تدْنو ضَرْبةً مِنْ مَسْكنِكَ. لأنَّهُ يوصى مَلائِكتَهُ بِكَ. ليَحْفظونكَ فى جَميعِ طُرقكَ. وعَلَى أيْديهِمْ يحْمِلونَكَ، لئَلاّ تَعْثُر بحَجَرٍ رِجْلُكَ. تَطأُ الأفْعَى ومَلِكَ الحيّات، وتَسْحقُ الأسَدَ والتِّنّينَ. لأنَّهُ تَعلَّقَ بى فَأنجّيه، أُرفِّعُهُ لأنَّهُ عَرفَ اسْمى. يدْعونى فأسْتجيب لَهُ، مَعهُ أَنا فى الشِّدَّة، أنْقِذهُ وأمَجِّدهُ ومِنْ طولِ الأيّامِ أشْبِعُهُ، وأُريهِ خَلاصى. هَلِّلُيلويا. + +++",
  "92": "الرَّبُّ قَدْ مَلكَ (†) الرَّبُّ قَدْ مَلكَ، لَبِسَ الجَلالَ. لَبِسَ الرَّبُّ القُوَّةَ وتَمنْطَقَ بِها، لأنَّهُ ثَبتَ المسْكونَة فَلَن تَتَزعْزَعَ. كُرْسِيُّكَ ثابتٌ مُنْذُ البَدءِ وأنْتَ هُوَ مُنْذُ الأزَل. رَفَعتِ الأنْهارُ يا رَبُّ، رَفَعتْ الأنْهارُ صَوتَها. تَرفَعُ الأنْهارُ صَوتَها، مِنْ صَوتِ مِياهٍ كَثيرةٍ. عَجيبَةٌ هِىَ أمْواجُ البَحْر، بَلْ عَجيبٌ هُوَ الرَّبُّ فى الأَعالى. شهاداتُهُ صادِقةٌ جداً، لبَيْتِكَ ينْبَغى التَّقديسُ يا رَبُّ طول الأيّامِ. هَلِّلُيلويا. + +++",
  "95": "سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً (†) سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً، سَبِّحى الرَّبَّ يا كُلَّ الأرْضِ. سَبِّحوا الرَّبَّ وبارِكوا إسْمَهُ، بَشِّروا مِنْ يَومٍ إلَى يَومٍ بِخَلاصِهِ. حَدِّثوا فى الأممِ بمَجْدِهِ، بَيْنَ جَميعِ الشُّعوبِ بعَجائِبهِ. لأنَّ الرَّبَّ عَظيمٌ هُوَ ومُسَبحٌ جِداً، مَهوبٌ عَلَى كُلِّ الآلِهَةِ. لأنَّ كلَّ آلِهَةِ الأممِ شَياطينُ أمّا الرَّبُّ فَصَنَعَ السَّمَواتِ. الجَلالُ والبَهاءُ قُدّامَهُ، الطُّهْرُ والجَمالُ العَظيمُ فى قُدْسِه. قَدِّموا للرَّبِّ يا جَميعَ قَبائِل الأممِ، قَدِّموا للرَّبِّ مَجْداً وكَرامَةً. قَدِّموا للرَّبِّ مَجْداً لاسْمِهِ، احْملوا الذَّبائِحَ وادْخُلوا دِيارَهُ. اسْجُدوا للرَّبِّ فى دِيارهِ المقَدَّسةِ، فَلْتَتَزَلْزَل الأرْضُ كُلُّها أمامِ وجْهِهِ. قولوا بَيْنَ الأممِ إنَّ الرَّبَّ قَدْ مَلَكَ عَلَى خَشَبَةٍ، وأيْضاً ثَبَّتَ المسْكونَةَ فَلَنْ تُزَعْزَع. يدينُ الشُّعوبَ بالاسْتِقامَةِ، فلْتَفْرَح السَّمَوات ولتَبْتَهِج الأرْضُ. وليَعج البَحْر وجَميع مِلْئِهِ، تَفْرحُ الودْيانُ وكُلُّ ما فيها. حينَئذٍ يبْتَهجُ كُلُّ شَجَرِ الغابِ أمامَ وَجْهِ الرَّبِّ لأنَّهُ يأتى. يَأْتى لِيَدينَ الأرْضَ. يَدينَ المسْكونَةَ بالعَدْلِ، والشُّعوبَ بالاسْتِقامةِ. هَلِّلُيلويا. + +++",
  "96": "الرَّب قَدْ مَلَكَ فلْتَتَهلَّل الأرْضُ الرَّب قَدْ مَلَكَ فلْتَتَهلَّل الأرْضُ، ولْتَفْرح الجَزائِرُ الكَثيرةُ. سَحابٌ وضَبابٌ حَوْلهُ، العَدلُ والقَضَاءُ قوامُ كُرْسِيِّه. النّارُ تَسْبقُ فَتَسْلك أمامَه، وبلهيبٍ تَحْرقُ أعْداءهُ الَّذينَ حَوْلهُ. أضاءَت بُروقُهُ المسْكونَة، نَظَرت الأرْضُ فَتَزلْزَلت. ذابت الجِبالُ مِثلَ الشَّمْع مِنْ وَجْهِ الرَّبِّ ومِنْ وَجْه الأرْضِ كُلِّها. أخْبرَت السَّمَوات بِعَدْلهِ وعايَنَت جَميعُ الشُّعوبِ مَجْدَه. يَخْزَى جَميعُ السّاجدينَ لِصَنعةِ الأيْدى، المُفْتَخِرينَ بأصْنامِهِم. اسْجُدوا للَّهِ يا جَميعَ ملائِكتِهِ. سَمعَتْ صهْيونُ فَفَرحَتْ، وتَهلَّلَت بناتُ يَهوذا مِنْ أجْل أحْكامِكَ يا رَبُّ لأنَّكَ أنْتَ هُوَ الرَّبُّ العالى عَلَى كُلِّ الأرْضِ. ارْتَفَعْتَ جِدّاً فَوقَ جَميعٍ الآلِهَةِ. يا مُحبّى الرَّبِّ أَبْغِضوا الشَّرَّ. إنَّ الرَّبَّ يَحْفظُ نُفوسَ أبْرارِه ويُنَجِّيهِم مِنْ أيْدى الخُطاةِ. نورٌ أشْرقَ للصَّدّيقيَن. وفَرحٌ للمُسْتَقيمي القُلوبِ افْرَحوا أيُّها الصِّدّيقون بالرَّبِّ، واعْتَرفوا لذِكْرِ قَداستِهِ. هَلِّلُيلويا. + +++",
  "97": "سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً سَبِّحوا الرَّبَّ تَسْبيحاً جَديداً، لأنَّ الرَّبَّ قّدْ صَنَع أعْمالاً عَجيبَةً. خَلَّصَت لَهُ يَمينَهُ وذِراعَهُ القُدّوسَ. أعْلنَ الرَّبُّ خَلاصَهُ، وكَشَفَ قُدّامَ الأممِ عَدْلهُ. ذَكَرَ رَحْمتَهُ ليَعْقوبَ وحقَّهُ لبَيْتِ إسْرائيلَ. نَظَرَتْ أَقاصى الأرْضِ جَميعاً خَلاصَ إلَهِنا. هَلِّلُوا للرَّبِّ يا كُلَّ الأرْضِ، سَبِّحوا وهَلِّلُوا ورَتِّلوا. رَتِّلوا للرَّبِّ بالقيثارَةِ، بالقيثارَةِ وصَوتِ المزْمارِ، بأبْواقٍ خافِقَةٍ وصَوْتِ بوقِ القَرْن، هَلِّلُوا أمامَ الرَّبِّ الملِكِ. فَلْيعج البَحْرُ وكُلُّ مِلئِهِ. المسْكونَة وكُلُّ السّاكِنينَ فيها، تُصفِّقُ جَميعُ الأنْهارِ، الجِبالُ تَبْتهجُ أمامَ وَجْه الرَّبِّ. لأنَّهُ أتَى ليَدينَ الأرْضَ، يَدينُ المسْكونَةَ بالعَدْلِ والشُّعوبَ بالاسْتِقامةِ. هَلِّلُيلويا. + +++",
  "98": "الرَّبُّ قَدْ مَلَكَ فَلْتَرتَعِد الشُّعوبُ الرَّبُّ قَدْ مَلَكَ فَلْتَرتَعِد الشُّعوبُ، الجالِسُ عَلَى الشّاروبيم فَلْتَتَزَلْزل الأرْضُ. عَظيمٌ هُوَ الرَّبُّ فى صِهْيونَ، ومُتَعالٍ عَلَى كُلِّ الشُّعوبِ. فَلْيَعْتَرفوا لإسْمِكَ العَظيم، لأنَّهُ مرْهوبٌ وقُدّوسٌ، وكَرامَةُ الملِكِ أنْ يُحبَّ العَدْلَ. أنْتَ هَيَّأتَ الاسْتِقامَةَ، أنْتَ أجْريْتَ القَضاءَ والعَدلَ فى يَعْقوب. ارْفَعوا الرَّبَّ إلَهَنا، واسْجُدوا لموْطِئ قَدَمَيْه فإنَّه قُدّوسٌ هُوَ، موسَى وهَرونُ بَينَ كَهَنتِهِ، وصَموئيلُ بَينَ الذينَ يَدْعونَ باسْمِهِ، كانوا يَدْعونَ الرَّبَّ فَيسْتَجيبُ لَهُم، بعَمودِ الغَمامِ كانَ يُكلِّمهُم. لأنَّهُم حَفِظوا شَهاداته، والأوامرَ الَّتى أعْطاهُم. أيُّها الرَّبُّ إلهُنا أنْتَ اسْتَجبْتَ لَهُم، صِرْتَ لَهُم يا اللَّهُ غَفوراً ومنْتَقماً عَلَى جَميعِ أعْمالِهِم، ارْفَعوا الرَّبَّ إلَهَنا، واسْجُدوا فى جَبَلِه المقَدَّس فإنَّ الرَّبَّ إلَهَنا قُدّوسٌ. هَلِّلُيلويا. + +++",
  "99": "هَلِّلُوا للرَّبِّ يا كُلّ الأرْضِ هَلِّلُوا للرَّبِّ يا كُلّ الأرْضِ، اعْبدوا الرَّبَّ بالفَرَحِ، ادْخُلوا أمامَهُ بالتَّهْليلِ، اعْلَموا أنَّ الرَّبَّ هُوَ إلَهنا. هُوَ صَنَعَنا ونَحْنُ لَهُ، نَحْنُ شَعْبُهُ وغَنَمُ رعيَّتِهِ، ادْخُلوا أبْوابَهُ بالاعْتِراف، ودِيارَه بالتَّسابيحِ، اعْتَرفوا لَهُ وبارِكوا اسْمَهُ، فإنَّ الرَّبَّ صالحٌ هُوَ.وإلَى الأبَدِ رحْمَتُه، وإلَى جيلٍ فَجيلٍ حَقُّهُ. هَلِّلُيلويا. + +++",
  "100": "لرَحْمتِكَ وعَدْلكَ لرَحْمتِكَ وعَدْلكَ أُسَبِّحُكَ يا رَبُّ، أترنَّمُ لَكَ وأتَفهَّمُ فى طَريقٍ بلا عَيبٍ. مَتَى تَأْتى إلَىَّ؟ كنْتُ أسْلُكُ بِدَعةِ قَلبى فى وَسَطِ بَيْتى، لَمْ أضَعْ أمامَ عَينَىَّ أمْراً يُخالِفُ النّاموسَ. صانِعى المعْصِيةِ أبْغَضْتُ. لَمْ يَلْصَقْ بِىَ قَلبٌ مُعوجٌ، وعنْدَ مَيَلانِ الشَّرّير عَنّى لَمْ أكُنْ أعْلم والَّذى يَغْتابُ قَريبَهُ سِرّاً كنتُ أُطاردُهُ، المسْتَكبرُ بعيْنَيهِ والمنْتَفخُ القَلْب لَمْ أواكِلهُ. عَيْناىَ عَلَى جَميعِ أُمَناءِ الأرْضِ لِكَىْ أُجْلِسَهُم مَعى، السّالِكُ فى الطَّريقِ بِلا عَيبٍ، هَذا كانَ يخْدُمنى. المتَكبِّرُ لَمْ يَسْكُنْ فى وَسَطِ بَيْتى، المتَكلِّمُ بالظُّلمِ لَمْ يَسْتَقِمْ أمامَ عَيْنىَّ، فى أوْقاتِ الغَدَوات كُنتُ أقْتلُ جَميعَ خُطاةِ الأرْضِ، لأبيدَ مِنْ مَدينَةِ الرَّبِّ جَميعَ صانِعى الإثْمِ. هَلِّلُيلويا. + +++",
  "109": "قالَ الرَّبُّ لِرَبّى قالَ الرَّبُّ لِرَبّى اجْلسْ عَنْ يَمينى، حَتَّى أَضع أعْدائِكَ عِنْدَ مَوْطئ قَدَميْكَ. عَصا قُوَّة يُرْسلُ لَكَ الرَّبُّ مِنْ صِهْيون، فَتَسودُ فى وَسَطِ أعْدائِكَ. مَعَكَ الرِّياسَةُ فى يَومِ قُوَّتِكَ فى بَهاءِ القدّيسينَ. مِن البَطْنِ قَبْل كَوْكبِ الصُّبْح وَلدتكَ. أَقْسَمَ الرَّبُّ ولَنْ يَنْدَم، أنَّكَ أنْتَ هُوَ الكاهِنُ إلَى الأبدِ عَلَى طَقْسِ مَلْكى صادَق. الرَّبُّ عَنْ يَمينِكَ، يُحطِّمُ فى يَوْمِ رِجْزِهِ مُلوكاً، يَقْضى بَينَ الأممِ، يَمْلأ الأرْضَ جُثَثاً. يَسْحقُ رؤوسَ كَثيرينَ عَلَى الأرْضِ، وفى الطَّريقِ يَشْربُ الماءَ مِنَ الْوادى. لذَلِكَ يرْفَعُ رَأسَه. هَلِّلُيلويا. + +++",
  "110": "أعْتَرفُ لَكَ يا رَبُّ أعْتَرفُ لَكَ يا رَبُّ مِنْ كُلِّ قَلبى، فى مَجْلسِ المسْتَقيمينَ وفى مَجْمَعِهِم. عَظيمةٌ هِىَ أعْمالُ الرَّبِّ، ومَشيئاتُه كُلُّها مفْحوصةٌ. جَلالٌ وبَهاءٌ عَملُهُ، وعَدْلهُ دائمٌ إلَى الأبَدِ. ذَكَرَ جَميعَ عَجائِبهِ، رَحيمٌ هُوَ الرَّبُّ ورَؤوفٌ. أعْطَى طعاماً لأتْقِيائِهِ، يَذكُرُ إلَى الدَّهرِ ميثاقَهُ، أخْبَرَ شَعبهُ بِقُوةِ أعْمالِهِ، لِيُعطيهُم ميراثَ الأممِ. أعْمالُ يَدَيهِ حَقٌّ وعَدْلٌ، كُلُّ وَصاياهُ صادقَةٌ ثابتَةٌ إلَى دَهْر الدُّهورِ، مَصْنوعَةٌ بالحَقِّ والإسْتِقامَةِ. أرْسَلَ خَلاصاً لشَعْبهِ، أمَرَ بعهْدِهِ إلَى الأبدِ. اسْمُهُ قُدّوسٌ مَرْهوبٌ، رأسُ الحِكْمَةِ مَخافةُ الرَّبِّ، والفَهْمُ صالحٌ لِكُلِّ مَنْ يَعْملُ بِهِ. وتسْبِحَتُه دائِماً إلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "111": "طوبَى للرَّجُل الخائِفِ الرَّبِّ طوبَى للرَّجُل الخائِفِ الرَّبِّ، ويَهْوَى وَصاياه جِدّاً، يُقَوّى نَسْلهُ عَلَى الأرْضِ، جيلُ المسْتَقيمينَ يُبارَكُ. مَجْدٌ وغِنى فى بَيْتِهِ، وبرُّهُ يَدومُ إلَى الأبَدِ. نورٌ أشْرَقَ فى الظُّلْمةِ للمُسْتَقيمينَ، الرَّبُّ الإلهُ رَحيمٌ ورَؤوفٌ وبارٌّ. صالِحٌ هُوَ الرَّجُلُ الَّذى يَتَرَأَّفُ ويُقْرِضُ. يُدبِّرُ أقْوالَهُ بالحَقِّ، لأنَّهُ لا يَتزعْزَعُ إلَى الدَّهرِ، ذِكْرُ الصِّدّيقِ يَدومُ إلَى الأبَدِ، لا يَخْشَى مِنْ خَبرِ السّوءِ. قلْبُهُ ثابتٌ فَلا يَتزعْزَعُ حتَى يَرَى بأعْدائِهِ. فَرَّقَ أعْطَى المساكينَ، برُّهُ دائمٌ إلَى دَهْرِ الدُّهورِ. يَرتَفع قَرنَهُ بالمجْدِ. الخاطئُ يُبْصرُ فَيغْتاظ، ويُصرُّ بأسْنانِه ويَذوبُ. شَهْوةُ الخاطئ تبيدُ. هَلِّلُيلويا. + +++",
  "112": "سبِّحُوا الرَّبِّ أيُّها الفتِيانُ سبِّحُوا الرَّبِّ أيُّها الفتِيانُ، سَبِّحُوا إسْمَ الرَّبِّ. لِيَكُنِ اسْمُ الرَّبِّ مُبارَكاً مِنَ الآنِ وإلى الأبَدِ. مِنْ مَشَارقِ الشَّمْسِ إلى مَغارِبِها بَاركُوا اسْمَ الرَّبِّ. الرَّبُّ عَالٍ عَلى كلِّ الأمُمِ، فَوْقَ السَّمَوات مَجْدهُ. مَنْ مِثْلُ الرَّبِّ إلَهنَا السَّاكِنِ فى الأعَالى، النَّاظِرِ إلى المتَواضِعِينَ فى السَّماءِ وعَلى الأرْضِ. المقِيمِ المسْكِينَ مِنَ التُّرابِ، الرَّافِع البَائِسِ مِنَ المزْبَلةِ، لِكىْ يُجْلسَهُ مَعَ رُؤسَاءِ شَعْبهِ. الذِى يَجْعلُ العَاقِرَ ساكِنَة فى بَيْتٍ، أمَّ أوْلادٍ فرِحةً. هَلِّلُيلويا. + +++",
  "114": "أحْببتُ أَنْ يَسْمعَ الرَّبُّ أحْببتُ أَنْ يَسْمعَ الرَّبُّ صَوتَ تَضَرُّعى، لأنَّهُ أمالَ أُذنَهُ إلَىَّ فأدْعوهُ كُلَّ أيّامى. لأَنَّ أوْجاعَ الموْتِ اكْتَنَفتْنى، وشَدائِدَ الجَحيمِ أصابَتنى، ضيقاً وحُزْنا وَجَدت. وباسْم الرَّبِّ دَعوت. يا رَبُّ نَجِّ نَفْسى. الرَّبُّ رَحيمٌ وصِدّيقٌ، وإلَهنا يَرْحَمُ. الَّذى يَحْفظُ الأطْفالَ هُوَ الرَّبُّ، إتَّضَعْتُ فَخلِّصنى. ارْجِعى يا نَفْسي إلَى مَوْضِعِ راحَتكِ، لأنَّ الرَّبَّ قَدْ أحْسَنَ إلَىَّ وأنْقَذَ نَفْسى مِنَ الموْتِ، وعَيْنَىَّ مِنَ الدُّموعِ، ورِجْلَىَّ مِنَ الزَّلَلِ. أرْضَى الرَّبّ أماَمه فى كورَةِ الأحْياءِ. هَلِّلُيلويا. + +++",
  "115": "آمَنْتُ لِذلِكَ تَكلَّمْتُ آمَنْتُ لِذلِكَ تَكلَّمْتُ، وأَنا اتَّضَعتُ جِدّاً. أَنا قلْتُ فى حَيْرتى أنَّ كُلَّ النّاسِ كاذِبونَ. بِماذا أُكافِئُ الرَّبَّ عَنْ كُلِّ ما أعْطانيهِ؟ كأْسُ الخَلاصِ آخُذُ وباسْمِ الرَّبِّ أدْعو. أُوفى نُذورى للَّرِّب قُدّامَ كُلِّ شَعْبِهِ. كَريمٌ أمامَ الرَّبِّ مَوْت قِدّيسيهِ. يا رَبُّ أَنا عَبْدكَ، أَنا عَبْدكَ. وابْنُ أمَتِكَ. قَطَعْتَ قُيودى. فَلَكَ أذْبَحُ ذَبيحةَ التَّسْبيحِ. وباسْمِ الرَّبِّ أدْعو. أُوفى للرَّبِّ نُذورى، فى دِيارِ بَيتِ الرَّبِّ، قُدّامَ كُلِّ شَعْبِهِ، فى وَسَطِ أورُشَليم. هَلِّلُيلويا. + +++",
  "116": "سَبِّحوا الرَّبَّ يا جَميعَ الأممِ سَبِّحوا الرَّبَّ يا جَميعَ الأممِ، ولتُبارِكهُ كافَّةُ الشُّعوبِ، لأنَّ رَحْمَتَهُ قَدْ قَويَتْ عَليْنا، وحَقُّ الرَّبِّ يَدومُ إلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "117": "اعْتَرفوا للرَّبِّ لأنَّهُ صالِحُ اعْتَرفوا للرَّبِّ لأنَّهُ صالِحُ وأنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ بَيْتُ إسْرائيلَ أنَّهُ صالِحٌ وأنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ بَيْتُ هَرونَ أنَّهُ صالِحٌ وأنَّ إلَى الأبَدِ رَحْمَتَهُ. لِيَقُلْ أتْقِياءُ الرَّبِّ أنَّهُ صالِحٌ وأنَّ إلَى الأبَدِ رَحْمَتَهُ. فى ضيقَتى صَرَخْتُ إلَى الرَّبِّ، فاسْتَجابَ لى واخْرجَنى إلَى الرَّحْبِ. الرَّبُّ عَوْنى فَلا أخْشَى، ماذا يَصْنعُ بى الإنْسانُ؟ الرَّبُّ لى مُعينٌ، وأنا أرَى بأعْدائى. الإتِّكالُ عَلَى الرَّبِّ خَيْرٌ مِنَ الإتِّكالِ عَلَى البَشَرِ. الرَّجاءُ بالرَّبِّ خَيْرٌ مِنَ الرَّجاءِ بالرُّؤَساءِ. كُلُّ الأممِ أَحاطوا بى، وباسْمِ الرَّبِّ انْتَقَمتُ مِنْهُمْ. أَحاطوا بى احْتِياطًا واكْتَنَفونى وباسْمِ الرَّبِّ قَهَرْتُهُمْ. أَحاطوا بي مِثْلَ النَّحْلِ حَولَ الشَّهْدِ، والْتَهَبوا كَنارٍ فى شَوْكٍ، باسْمِ الرَّبِّ انْتَقمْتُ مِنْهُم. دُفِعْت لأَسْقُطَ والرَّبّ عَضدَنى. قُوَّتى وتَسْبِحَتى هُوَ الرَّبُّ، وقَدْ صارَ لى خَلاصاً. صَوْتُ التَّهْليلِ والخَلاصِ فى مَساكِنِ الأبْرارِ، يَمينُ الرَّبِّ صَنَعَتْ قُوَّةً، يَمينُ الرَّبِّ رَفَعَتْنى، يَمينُ الرَّبِّ صَنَعَتْ قُوَّةً فَلَنْ أَموت بَعْدَ، بَلْ أحْيا وأُحَدِّثُ بأعْمالِ الرَّبِّ، تأْديبًا أدَّبَنى الرَّبُّ. وإلَى الموْتِ لَمْ يُسلِمنى. افْتَحوا لى أبْوابَ البِرِّ، لِكَىْ أدْخُلَ فيها وأعْتَرف للرَّبِّ. هَذا هُوَ بابُ الرَّبِّ، والصِّدّيقونَ يَدْخُلونَ فيهِ. أعْتَرفُ لَكَ يارَبُّ، لأنَّكَ اسْتَجَبْتَ لى وكُنتَ لى مُخلِّصًا. الحَجَرُ الَّذى رَذَلهُ البَنّاؤونَ، هَذا صارَ رَأْسًا للزّاوِيةِ. مِنْ قِبَلِ الرَّبِّ كانَ هَذا وهُوَ عَجيبٌ فى أعْيُننا. هَذا هُوَ اليَوْمُ الَّذى صَنَعَهُ الرَّبُّ، فَلْنَبْتَهجُ ونَفْرَحُ فيهِ. يا رَبُّ خَلِّصْنا، يارَبُّ سَهِّلْ سُبُلَنا، مُبارَكٌ الآتى باسْمِ الرَّبِّ، بارَكْناكُم مِنْ بَيْتِ الرَّبِّ، اللَّهُ الرَّبّ أضاءَ عَلَيْنا. رَتِّبوا عيداً بِمَوْكِبٍ حَتَّى قُرونِ المذْبَحِ، أنْتَ هُوَ إلَهى فأشْكُركَ، إلَهى أنْتَ فَأَرْفَعكَ. أعْتَرفُ لَكَ يا رَبُّ، لأنَّكَ اسْتَجَبتَ لى وصِرْتَ لى مُخلِّصًا. اشْكُروا الرَّبَّ فإنَّه صالحٌ وأنَّ إلَى الأبَدِ رَحْمتُهُ. هَلِّلُيلويا. + +++",
  "118": "طوباهُمْ الذينَ بلا عَيْبٍ (1) طوباهُمْ الذينَ بلا عَيْبٍ فى الطّريقِ، السّالكونَ فى ناموسِ الرّبِّ. طوباهُمْ الذينَ يَحفظونَ شهاداتِهِ، ومنْ كُلِّ قُلوبِهِم يَطلبونَهُ. لأنَّ صانِعى الإثمَ لم يَهْوَوْا أن يَسلكوا فى سُبُلِهِ. أنتَ أمَرتَ أن تُحفَظَ وَصاياكَ جِداً، فيا ليْتَ طُرُقى تَستقيمُ إلى حفظِ حُقوقِكَ. حينئذٍ لا أخزَى إذا تَطلّعتُ إلى جَميعِ وَصاياكَ. أشْكرُكَ يا رَبُّ باستقامَةِ قَلبى، إذ عَرفتُ أحْكام عَدلِكَ. حقوقُكَ أحفظُ، فلا تَرفُضنى إلى الغايَةِ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (2) بماذا يُقَوِّمُ الشّابُ طَريقَهُ؟ بحِفظِهِ أقْوالِكَ. من كُلِّ قَلبى طَلبتُكَ، فلا تُبعِدْنى عن وَصاياكَ. أخْفَيتُ أقوالَكَ فى قَلبى لِكَى لا أُخْطِئُ إليكَ. مُباركٌ أنتَ يا رَبُّ، عَلّمنى حُقوقكَ. بشفَتَىَّ أخْبرتُ بكُلِّ أحْكامِ فَمكَ، وفَرحتُ بطَريقِ شِهاداتِكَ كما بكُلِّ غِنَى. فى وَصايَاكَ أتَأمّلُ، وأتَفَهَّمُ فى طُرقِكَ. بفَرائضِكَ ألْهَجُ، ولا أنْسى كلامكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (3) كافِئْ عَبدَكَ فأحيا، وأحفظُ أقوالَكَ. اكشِفْ عن عَينَىَّ فاُبصرُ عَجائبَ ناموسِكَ. غَريبٌ أنا فى الأرضِ، فلا تُخْفِ عَنى وَصاياكَ. اشْتاقتْ نَفسى إلى اشْتهاءِ أحْكامِكَ فى كُلِّ حينٍ. إنّكَ انتَهرتَ المُتكبّرينَ المَلاعينَ، الذينَ حادوا عن وَصاياكَ. انزَعْ عنى العارَ والخزْىَ، فإنّى لشهاداتِكَ ابْتَغيْتُ. جَلسَ الرّؤساءُ وتَقَاوَلوا علىَّ، أما عَبدُكَ فكانَ يَهتمُّ بحُقوقِكَ لأنَّ شهاداتِكَ هى دَرسى، وحُقوقَكَ هى مَشورَتى. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (4) لَصقتْ بالترابِ نَفْسى، فاحْينى كَكلِمَتِكَ. أخْبرتُ بطُرقِكَ، فاسْتَجِبْ لى. عَلّمنى حُقوقَكَ، وطَريق عَدلِكَ فَهّمنى، فألْهجُ فى عَجائِبِكَ. ذَبلتْ نَفْسى من الحُزن فثَبّتنى فى أقوالكَ، طَريق الظّلم ابعدْ عَنّى، وبناموسِكَ ارْحَمنى. إنّى اختَرتُ طريقَ الحقِّ، وأحْكامكَ لم أنْس. لَصقتُ بشِهاداتكَ يا رَبُّ فلا تُخزِنى. فى طَريق وَصاياكَ سَعيتُ عندما وَسعتَ قَلبى. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (5) ضَعْ لى يا رَبُّ ناموساً فى طَريقِ حُقوقِكَ، فأتبعهُ كُلّ حينٍ. فَهّمنى فأبحثُ عن ناموسِكَ، وأحفظهُ بكُلّ قَلبى. اهْدنى فى سَبيلِ وَصاياكَ، فإنّى إيّاها هَوَيتُ. املْ قَلبى إلى شِهاداتِكَ لا إلى الظّلْمِ. ارْدُدْ عَينىَّ لئلا تُعايِنا الأباطيلَ، وفى سُبُلِكَ احْيِنى. ثَبّتْ قَولكَ لعبدِكَ فى خَوفِكَ، وانْزَعْ عنّى العارَ الذى حُذِّرتُ مِنه فإنّ أحْكامَكَ حُلوةُ، ها قد اشْتهيتُ وَصاياكَ فاحيْنى بعدلِكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (6) لتأتِ علىَّ رَحمتُكَ يا رَبُّ، وخَلاصُكَ كقَولِكَ فأجيبُ مُعَيِّرِىَّ بكلمةٍ. لأنى اتّكلتُ على أقوالِكَ. لا تَنْزع من فَمى قولَ الحَقِّ، لأنّى تَوكّلتُ على أحْكامِكَ. وأحفظُ شَريعَتَكَ فى كُلِّ حينٍ، وإلى الأبَدِ وإلى مَدَى الدّهرِ. كُنتُ أسْلكُ فى السِّعَة، لأنّى لوَصياكَ ابتَغيْتُ. وتَكلمّتُ بشهادتِكَ قُدّامَ المُلوكِ ولم أخْز، ولَهَجْتُ بوَصاياكَ التى أحبَبْتُها جداً. ورَفعتُ يَدىّ إلى وَصاياكَ التى وَدَدتُها جداً، وتَأمّلتُ فرائضَكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (7) اذكُرْ لعبدِكَ كلامَكَ الذى جَعلتنى عليهِ أتّكل. هذا الذى عَزّانى فى مَذلّتى، لأنّ قَولَكَ أحيانى. إن المُتكبرين تَجاوَزوا النّاموسَ إلى الغايَةِ، أما أنا فعَنْ ناموسِكَ لم أمِلْ. تَذكّرتُ أحْكامَكَ يا رَبُّ منذُ الدّهرِ فتَعزّيتُ. الكآبةُ مَلكتْنى من أجلِ الخُطاةِ الذينَ تَركوا ناموسَكَ. حُقوقُكَ كانتْ لى مَزاميرَ فى مَوضعِ غُربَتى. ذَكَرتُ فى الليلِ اسْمَكَ يا رَبُّ وحَفَظتُ شَريعتَكَ، هذا صارَ لى لأنّى طَلبتُ حُقوقَكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (8) نَصيبى أنتَ يا رَبُّ، فقلتُ أنْ أحفظَ وَصاياكَ. تَرضَّيْتُ وَجهَكَ بكُلِّ قَلبى، فارْحَمنى كقَولِكَ. تَفكّرتُ فى طُرُقكَ، فرَدَدْتُ قَدمىَّ إلى شِهاداتكَ. أسْرَعتُ ولم أتَوانْ عن حفظِ وَصاياكَ. رباطاتُ الخُطاة الْتَفّت علىَّ، أما شَريعَتُكَ فلم أنْسها. فى نِصفِ الليلِ نهَضتُ لأشْكرُكَ على أحْكامِ عَدلِكَ. شريكٌ أنا لكُلّ الذينَ يَخافونَكَ وللحافِظين وَصاياكَ. من رَحمَتِكَ يا رَبُّ امتَلأتْ الأرْضُ، فعَلّمنى عَدْلَكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (9) خَيراً صَنعتَ مع عَبدِكَ، يا رَبُّ حَسَب قَولِكَ. صَلاحاً وأدَباً ومَعرفةً عَلّمنى، لأنى قد صَدّقتُ وَصاياكَ. قَبل أن أذلل أنا تَكاسَلتُ، والآن حَفظتُ كلامكَ. صالحٌ أنتَ يا رَبُّ، فبصَلاحِكَ عَلّمنى حُقوقكَ. كَثُرَ علىَّ ظُلمُ المُتكبّرينَ، وأنا بكُلّ قَلبى أبْحَثُ عن وَصاياكَ. تجبن مثل اللبن قلوبَهُم، وأنا لَهَجْتُ بناموسِكَ: خَيرٌ لى أنّكَ أذللتَنى حتى أتَعلّمُ حُقوقَكَ. ناموسُ فَمِكَ خَيرٌ لى من ألوفِ ذَهبٍ وفِضَّةٍ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (10) يَداكَ صَنعَتانى وجَبَلتانى. فهّمنى فأتَعلّمُ وَصاياكَ. الذينَ يَخافونَكَ يُبصرونَنى ويَفرَحونَ، لأنى بكلامِكَ وَثقتُ. قد عَلِمتُ يا رَبُّ أن أحْكامَكَ عادلَةٌ، وبحقٍ أذْلَلتنى. فلتأتِ علىَّ رَحمتُكَ لتُعزّينى، نَظير قَولِكَ لعَبدِكَ. لتَأتنى رَأفتُكَ فأحْيا، لأنّ ناموسَكَ هو دَرسى. ليَخْزَ المُتكبِّرون لأنَهم خالَفوا الشَّرعَ علىَّ ظُلماً. وأنا كنتُ مُثابراً على وَصاياكَ. ليَرجع إلىَّ الذينَ يتّقونَكَ ويَعرفونَ عجائبَكَ. ولَيصِر قَلبى بلا عَيْب فى عَدلكَ لكىْ لا أخزَى. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (11) تاقَتْ نَفْسى إلى خَلاصِكَ وعلى كلامِكَ تَوكّلتُ. كَلَّتْ عَيناىَ من النَظرِ إلى أقوالكَ، قائلتين: متى تُعزّينى؟! صِرتُ مِثلَ زُقٍ فى جَليدٍ، ولحُقوقِكَ لم أنْسَ. كم هىَ أيّامُ عَبْدِكَ؟ متى تُجرِى لى حُكماً على الذينَ يَضطهدونَنى؟ تَكلّمَ معى مُخالفو النّاموس بِكَلامِ هَذَيانٍ، ولكنْ ليسَ كناموسِكَ يا رَبُّ. لأنَّ كُلَّ وَصاياكَ هىَ حَقٌ، وبظُلمٍ طَردونى فأعنّى. كادوا يفْنونَنى من الأرضِ، أما أنا فلمْ أتْرُكْ وَصاياكَ. حَسَب رَحمَتكَ أحْينى فأحفَظُ شِهادات فَمكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (12) يا رَبُّ كلمَتُكَ دائمَةٌ فى السّمواتِ إلى الأبَدِ، وإلى جيلٍ فجيلٍ حَقّكَ، أسّسْتَ الأرضَ فهىَ ثابتةٌ بأمْرِك، والنّهارُ أيضاً ثابتٌ، لأنّ كُلَّ الأشْياءِ مُتعبّدَةٌ لكَ، ولو لم تَكنْ شَريعَتُكَ تلاوَتى لهَلَكتُ حينئذٍ فى مَذلّتى. إلى الدّهرِ لا أنسى وَصاياكَ، لأنّكَ بها أحْيَيْتَنى يا رَبُّ. لكَ أنا فخَلّصْنى يا رَبُّ، لأنى لوَصياكَ طَلبْتُ، إيّاىَ اِنتَظرَ الخُطاةُ ليُهلكونى، ولشهاداتكَ فَهمتُ. لكُلِّ تَمامٍ رأيْتُ مُنتَهَى، أما وَصاياَك فواسِعةٌ جداً. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (13) مَحبوبٌ هوَ اسْمِكَ يا رَبّ فهو طول النّهارِ تِلاوتى. عَلّمْتَنى وَصاياكَ أفضَلُ من أعْدائى، لأنها ثابتَةٌ إلى الأبَدِ. أكثَر من الذين يُعلّمونَنى فَهمتُ، لأنّ شِهاداتكَ هى دَرسى. أكثَر من الشّيوخِ فَهمتُ، لأنى طَلبتُ وَصاياكَ. من كُلّ طريقٍ خبيثٍ مَنَعْتُ رِجْلَىَّ، لكىْ أحفظُ كلامكَ. عن أحْكامكَ لم أحِدْ، لأنّكَ وَضعتَ لى ناموساً. إنّ كلماتكَ حُلوَة فى حَلْقى، أفضَلُ من العَسَلِ والشّهدِ فى فَمى. من وَصاياكَ تَفطّنتُ، فلهذا أبْغَضتُ كُلَّ طُرُقِ الظّلمِ لأنّكَ وَضعتَ لى ناموساً. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (14) مِصباحٌ لرجلىَّ كَلامُكَ ونورٌ لسَبيلى. حَلّفتُ فأقَمتُ على حفظ أحْكامِ عَدلِكَ. تَذلّلْتُ جِداً إلى الغَايَةِ يا رَبُّ احْينى كقَولِكَ. تَعهُّداتُ فَمى بَارِكْها يا رَبُّ، وأحْكامَكَ عَلّمنى. نَفسى فى يَديْكَ كُلَّ حينٍ، وناموسَكَ لم أنْسَ. أخْفَى لى الخُطاةُ فَخاً، ولم أضِلُّ عن وَصاياكَ. وَرثتُ شهاداتكَ إلى الأبَدِ، لأنَّها بَهْجَةُ قَلبى. عَطَّفتُ قَلبى لأصْنَع بِرَّكَ إلى الأبَد، من أجلِ المُكافأةِ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (15) لمتُجاوزى النّاموس أبغَضتُ، ولناموسِكَ أحبَبتُ، لأنّكَ أنتَ مُعينى وناصِرى، وعلى كلامِك تَوكّلتُ. ابْعِدوا عَنّى أيّها الأشْرارُ فأفحَصُ عن وَصايا إلَهى. عَضّدنى حَسَب قَولِك فأحْيا ولا تُخَيِّبْ رَجائى. اعِنّى فأخْلُص، وأدرِسُ فى وَصاياكَ كُلَّ حينٍ. رَذلتُ سائرَ الذينَ حادوا عن وَصاياكَ لأنّ فِكرَهُم ظُلمٌ. عُصاةً حَسَبتَ سائرَ خُطاة الأرضِ، فلهذا أحبَبتُ شِهاداتكَ فى كُلِّ حينٍ. سَمِّر خَوفَكَ فى لَحْمى، لأنى من أحْكامِكَ جَزعتُ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (16) قد أجْريتَ حُكماً وعَدلاً، فلا تُسَلّمنى إلى الذينَ يَظلمونَنى. كُنْ لعَبدِكَ كفيلاً فى الخَيْرِ لِئلا يَجوزُ علىَّ المُتكبّرونَ. عَيناىَ قد ذَبلتا مِن إنتظارِ خَلاصِكَ وقَول عَدلكَ. اصنَعْ مع عَبدكَ حسبَ رَحمتكَ، وحُقوقكَ عَلّمنى. عَبدُكَ أنا فَهّمنى فأعْرِف شِهاداتكَ. إنّه وَقتٌ يُعمَلُ فيهِ للرّبِّ، لأنّهم قد نَقَضوا ناموسَكَ. لأجْل هذا أحْبَبتُ وَصاياكَ أفضَل من الذّهَبِ والجَوهرِ. لأجْل هذا بإزاءِ كُلّ وَصاياكَ تَقَوَّمْتُ، وكُلّ طَريق ظلمٍ أبغَضتُ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (17) عَجيبَةٌ هى شِهاداتكَ، لذلك حَفَظّتْها نَفْسى. إعلانُ أقوالِكَ يُنيرُ لى، ويُفَهِّم الأطْفال الصّغار. فَتحْتُ فَمى واجتَذَبتُ لى روحاً، لأنى لوَصاياكَ اشْتَقتُ. انظُرْ إلىَّ وارْحَمنى، كرَحمتكَ للذينَ يُحبّونَ اسْمكَ. قَوِّمْ خَطواتى كقَوْلكَ، فلا يَتسلّط علىَّ أىُّ إثمٍ. انقِذنى من ظُلمِ النّاسِ فأحفظُ وَصاياكَ. اضِئ بوجهِكَ على عَبدِكَ وعَلّمنى حُقوقكَ. غاصَتْ عَيناىَ فى مَجارى المِياهِ، لأنهم لم يَحفظوا ناموسِكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (18) عادلٌ أنتَ يا رَبّ، وقضاؤكَ مُستقيمٌ. أوْصَيْتَ كثيراً بالعَدْلِ والحَقِ، اللذَيْنِ هُما شِهاداتكَ. غيرَةُ بَيْتِكَ أكلَتْنى لأنّ أعْدائى نَسوا وصاياك. مُمحَصٌ قَولكَ جداً، وعَبدكَ أحَبَّهُ. صَغيرٌ أنا ومَرذولٌ وحُقوقكَ لم أنْسَ. عَدلُكَ حقٌ هو إلى الأبَدِ، وكلامُكَ حقٌ هو. ضيقٌ وشدّةٌ أدْركانى، ووَصاياكَ هى دَرْسى. عادلةٌ هى شِهاداتكَ إلى الأبَدِ، فَهّمنى فأحْيا. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (19) صَرخْتُ من كُلّ قَلبى فاسْتَجبْ لى يا رَبّ، إنى أبْتَغى حُقوقَكَ. صَرخْتُ إليكَ فخَلّصنى، لأحفَظُ شِهاداتكَ. تَقدّمتُ قَبلَ الصبحِ وصَرخْتُ وعلى كلامِكَ تَوكّلتُ. سَبقتْ عَيْناىَ وَقت السَّحَر لألْهَجُ فى جَميعِ أقوالِكَ. فاسْمَعْ صَوتى يا رَبّ كرَحمتِكَ، وبحسبِ أحكامِكَ احْيِنى. اقْتَربَ بالإثمِ الذينَ يَطردونَنى، وعن ناموسِكَ ابتَعَدوا. قَريبٌ أنتَ يا رَبُّ وكُلّ وَصاياكَ حقٌ هىَ. مُنذُ البِدْءِ عَرفتُ من شِهاداتكَ أنّكَ إلى الدّهرِ أسَّسْتَها. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (20) انْظُرْ إلى مَذلّتى وانْقذْنى فإنّى لم أنْسَ ناموسَك. احْكم لى فى دَعواىَ ونَجّنى، من أجل كلامِكَ أحْينى. بَعيدٌ هو الخَلاصُ عن الخُطاةِ لأنّهم لم يَطلُبوا حُقوقِكَ. رَأفتُكَ كثيرَةٌ جداً يا رَبُّ، حَسب أحْكامِكَ احْيِنى. كثيرون هم الذينَ يَضطهِدونَنى ويُحزِنونَنى، وعن شِهاداتِكَ لم أجْنحْ. رأيْتُ الذينَ لا يَفهَمونَ فاكتَأبْتُ لأنّهم لأقْوالِكَ لم يَحفظوا. انظُرْ يا رَبُّ فإنى أحْبَبتُ وَصاياكَ، برَحمتِكَ يا رَبّ احْيِنى. بدءُ كلامِكَ حَقٌ وإلى الأبدِ كُلّ أحْكامِ عَدلكَ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (21) الرّؤساءُ اضطهَدونى بلا سَبَبٍ، ومن أقوالِكَ جَزعَ قَلبى. أبتَهجُ أنا بكلامِكَ، كمن وَجَدَ غَنائمَ كثيرةٍ. أبْغَضّتُ الظّلمَ ورَذَلتُهُ، أما ناموسكَ فأحْبَبتُهُ. سَبْعُ مَرّاتٍ فى النّهارِ سَبّحتُكَ على أحْكام عَدلكَ. فليكنْ سَلاٌمٌ عَظيمٌ للذينَ يُحبّون اسْمك، وليسَ لهمْ شَكٌ. تَوَقّعتُ خَلاصَكَ يا رَبُّ، ووَصاياكَ حَفظتُها. حَفظتْ نَفسى شِهاداتِكَ وأحْبَبْتَها جداً. حَفظتُ وَصاياكَ وشِهاداتكَ، وكُلّ طُرقى أمامكَ يا رَبُّ. (ذوكصاصى فيلا نيثروبى ... المجدُ لَكَ يا مُحبّ البَشَر). (22) فَلْيَدْنُ تَوسُّلى قُدّامكَ يا رَبُّ، كقَولكَ فَهِّمنى. فَلْتدخلْ طُلبتى إلى حَضرتِكَ يا رَبُّ، ككَلمتِكَ أحْيِنى. تَفيضُ شفتاىَ السبح، إذا ما عَلّمتَنى حُقوقكَ. لسانى يُجيبُ بأقوالِكَ، لأنّ جَميع وَصياكَ عادلّةٌ. لتَكنْ يَدكَ لخَلاصى لأنّى اشْتَهيتُ وَصاياكَ. اشْتقتُ إلى خَلاصِكَ يا رَبُّ، وناموسكَ هو تِلاوَتى. تَحيا نَفسى وتُسبّحُكَ. وأحْكامُكَ تُعينَنى. ضَللتُ مِثل الخَروفِ الضّالِ، فاطْلُبْ عَبدَكَ فإنّى لوَصاياكَ لم أنْسْ. هَلِّلُيلويا. + +++",
  "119": "إلَيْكَ يا رَبُّ صَرَخْتُ إلَيْكَ يا رَبُّ صَرَخْتُ فى حُزْنى، فاسْتَجَبْتَ لى. يا رَبُّ نَجِّ نَفْسى مِنَ الشِّفاهِ الظّالمةِ، ومِنَ اللِّسانِ الغاشِ، ماذا تُعْطَى وماذا تُزادُ أيُّها اللِّسانُ الغاشُّ؟ سِهامُ الأقْوياءِ مُرهَفةٌ مَعَ جَمْر البَرِّيَةِ. ويْلٌ لى فإنَّ غُرْبَتى قَدْ طالَت عَلَّى، وسَكنْتُ فى مَساكِن قيدار. طَويلاً سَكنَتْ نَفْسى فى الغُرْبَةِ، ومَعَ مُبْغِضى السَّلامِ كُنْتُ صاحِبَ سَلامٍ. وحينَ كُنتُ أُكَلِّمهُم بهِ كانوا يُقاتِلونَنى باطلاً. هَلِّلُيلويا. + +++",
  "120": "رَفَعْتُ عَيْنَيَّ إلَى الجِبالِ رَفَعْتُ عَيْنَيَّ إلَى الجِبالِ، مِنْ حَيْثُ يَأتى عَوْنى. مَعونَتى مِنْ عِنْدِ الرَّبِّ، الَّذى صَنَعَ السَّماءَ والأرْضَ. لا يُسَلِّمُ رِجْلَكَ للزَّللِ، فَما يَنْعسُ حافِظُك. هُوَذا لا يَنْعَسُ ولا يَنامُ حارِسُ إسْرائِيلَ. الرَّبُّ يَحْفَظُكَ، الرَّبُّ يُظلَّلُ عَلَى يَدِكَ اليُمْنَى. فَلا تَحْرقُكَ الشَّمْسُ بالنَّهارِ، ولا القَمَرُ باللَّيْلِ. الرَّبُّ يَحْفَظكَ مِنْ كُلِّ سوءٍ، الرَّبُّ يَحْفَظُ نَفْسَك. الرَّبُّ يَحْفَظُ دُخولَكَ وخُروجَكَ مِنَ الآنِ وإلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "121": "فَرحْتُ بالقائِلينَ لى فَرحْتُ بالقائِلينَ لى إلَى بَيْتِ الرَبِّ نّذْهَبُ. وَقَفَتْ أرْجلُنا فى أبْوابِ أورُشَليم. أورُشَليمُ المبْنِيَّةُ مِثْل مَدينَةٍ مُتَّصِلةٍ بَعْضُها ببَعْضٍ. لأَّن هُناكَ صَعِدَت القَبائِلُ، قَبائِلُ الرَّبِّ شَهادةً لإسْرائِيلَ. يَعْتَرِفونَ لإسْمِ الرَّبِّ. هُناكَ نُصِبَتْ كَراسِى للْقَضاءِ، كَراسى بَيْتِ داوُدَ. اسْأَلوا السَّلامَ لأورُشَليمَ، والخِصْبَ لِمُحِبِّيكِ، لِيَكُنْ السَّلامُ فى حِصْنِك، والخِصْبُ فى أبْراجِك الرَّصينَةِ. مِنْ أجْلِ إخْوَتي وأقارِبى، تَكَلَّمتُ مِنْ أجْلِك بالسَّلامِ. ومِنْ أجْلِ بَيْتِ الرَّبِّ إلَهِنا، الْتَمَسْتُ لَكِ الخَيْرات. هَلِّلُيلويا. + +++",
  "122": "إلَيْكَ رفَعْتُ عَيْنى إلَيْكَ رفَعْتُ عَيْنى يا ساكِنَ السَّماءِ. فَها هُما مِثْل عُيونِ العَبيدِ إلَى أيْدى مَواليهمْ، ومِثْل عَيْنَىْ الأمَةِ إلَى يَدَىْ سَيِّدَتِها. كَذَلِكَ أعْيُنُنا نَحْو الرَّبِّ إلَهِنا حَتَّى يَتَرأفَ عَلَيْنا. ارْحَمْنا يا رَبُّ ارْحَمْنا، فإنَّنا كَثيراً ما امْتَلأْنا هَواناً. وكَثيراً ما امْتَلأَتْ نُفوسُنا عاراً مِنَ المخَصِّبينَ، وإهانَةً مِنَ المتَعَظِّمينَ. هَلِّلُيلويا. + +++",
  "123": "لَوْلا أنَّ الرَّبَّ كانَ مَعنا لَوْلا أنَّ الرَّبَّ كانَ مَعنا لِيَقُلْ إسْرائيلُ. لَوْلا أنَّ الرَّبَّ كان مَعنا عِنْدَما قامَ النّاسُ عَلَيْنا. لابْتَلَعونا ونَحْنُ أحْياء، عِنْدَ سَخطِ غَضَبِهِمْ عَلَيْنا. إذَنْ لَغرَقْنا فى الماءِ، وجازَ عَلَى نُفوسِنا السَّيْلُ. بَلْ جازَ عَلَى نُفوسِنا الماءُ الَّذى لا نِهايَةَ لَهُ. مُبارَكٌ الرَّبُّ الّذى لَمْ يُسَلِّمْنا فَريسةً لأسْنانِهِم. نَجَتْ أنْفُسُنا مِثْلَ العُصْفورِ مِنْ فَخِّ الصَّيّادينَ، الفَخُّ انْكَسَرَ ونَحْنُ نَجَوْنا، عَوْنُنا بإسْمِ الرَّبِّ، الَّذى صَنَعَ السَّماءَ والأرْضَ. هَلِّلُيلويا. + +++",
  "124": "المتَوَكِّلونَ عَلَى الرَّبِّ المتَوَكِّلونَ عَلَى الرَّبِّ مِثْلُ جَبَلِ صِهْيونَ، لا يَتَزعْزَعُ إلَى الأبَد السّاكِنُ بأورُشَليمَ. الجِبالُ حَوْلَها والرَّبُّ حَوْلَ شَعبهِ مِنَ الآنَ وإلَى الأبَدِ. الرَّبُّ لا يَتْركُ عَصا الخُطاةِ تَسْتَقرُّ عَلَى نَصيبِ الصِّدّيقينَ. لِكَىْ لا يَمُدَّ الصِّدّيقونَ أيْدِيَهُم إلَى الإثْمِ. احْسِنْ يا رَبُّ إلَى الصّالِحينَ وإلَى المسْتَقيمى القُلوبِ. أمّا الَّذينَ يَميلونَ إلَى العَثَراتِ فيَنْزَعهُم الرَّبُّ مَعَ فَعَلةِ الإثْمِ. والسَّلامُ عَلَى إسْرائِيلَ. هَلِّلُيلويا. + +++",
  "125": "إذا ما رَدَّ الرَّبُّ سَبْىَ صِهْيونَ إذا ما رَدَّ الرَّبُّ سَبْىَ صِهْيونَ صِرْنا فَرِحينَ. حينَئِذٍ امْتَلأَ فَمُنا فَرحًا ولِسانُنا تَهْليلاً. حينَئِذٍ يُقالُ فى الأممِ إنَّ الرَّبّ قَدْ عَظَّمَ الصَّنيعَ مَعَهُم. عَظَّمَ الرَّبُّ الصَّنيعَ مَعَنا فَصِرْنا فَرِحينَ. ارْدد يا رَبُّ سَبْيَنا، مِثْلَ السُّيولِ فى الجَنوبِ. الَّذينَ يَزْرَعونَ بالدُّموعِ يَحْصُدونَ بالابْتِهاجِ. سَيْراً كانوا يَسيرونَ وهُمْ باكونَ حامِلينَ بِذارَهُم، ويَعودون بالفَرَحِ حامِلينَ أغْمارَهُم. هَلِّلُيلويا. + +++",
  "126": "إنْ لَمْ يَبْنِ الرَّبُّ البَيْتَ إنْ لَمْ يَبْنِ الرَّبُّ البَيْتَ، فَباطِلاً يَتْعبُ البَنّاؤُونَ. وإنْ لَمْ يَحْرُس الرَّبُّ المَدينَةَ. فَباطِلاً يَسْهرُ الحُرّاسُ. باطِلٌ هُوَ لَكُم التَّبْكيرُ. اِنْهَضُوا مِنْ بَعْدِ جُلوسِكُم يا آكِلي الخُبْزَ بالهُمومِ. فَإنَّهُ يَمْنَح أحِبّاءَهُ نَوْماً. البَنونَ ميراثٌ مِنَ الرَّبِّ، أُجْرَةُ ثَمَرَة البَطْنِ. كالسِّهامِ بِيَدِ القَوِيِّ، كَذلِكَ أبْناء الشَّبيبَةِ. مَغْبوطٌ هُوَ الرَّجُلُ الَّذي يَمْلأُ جُعْبَتَه مِنْهُم، حينَئِذٍ لا يُخْزَوْنَ إذا كَلَّموا أعْداءَهُم في الأبْوابِ. هَلِّلُيلويا. + +++",
  "127": "طوبَى لِجَميعِ الَّذينَ يتَّقونَ الرَّبَّ طوبَى لِجَميعِ الَّذينَ يتَّقونَ الرَّبَّ، السّالِكينَ فى طُرُقِه. تَأْكُلُ مِنْ ثَمَرةِ أتْعابِكَ، تَصيرُ مَغْبوطاً ويَكونُ لَكَ الخَيْر. إمْرأَتُكَ تَصير مِثْلَ كَرْمةٍ مُخْصِبَةٍ فى جَوانِبِ بَيْتِكَ، بَنوكَ مِثْلُ غُروسِ الزَّيْتونِ الجُددِ حَوْلَ مائِدَتكَ. هَكَذا يُبارَكُ الإنْسانُ المتَّقى الرَّبَّ. يُباركُكَ الرَّبُّ مِنْ صِهْيونَ، وتُبْصِرُ خَيْراتِ أورُشَليمَ جَميعَ أيّامِ حَياتِكَ. وتَرَى بَنى بَنيكَ، والسَّلامُ عَلَى إسْرائيلَ. هَلِّلُيلويا. + +++",
  "128": "مِرارًا كَثيرةً حارَبونى (†) مِرارًا كَثيرةً حارَبونى مُنْذُ صِباى لِيَقُلْ إسْرائيلُ. مِرارًا كَثيرةً قاتَلونى مُنْذُ شَبابى، وإنَّهُم لَمْ يَقْدِروا عَلَىَّ. عَلَى ظَهْرى جَلَدنى الخُطاةُ وأَطالوا إثْمَهُمْ. الرَّبّ صِدّيقٌ هُوَ، يَقْطعُ أعْناقَ الخُطاةِ، فَلْيَخْزَ وَلْيَرْتَدَّ إلَى الوَراءِ، كُلُّ الَّذينَ يُبْغِضونَ صِهْيونَ، وليَكونوا مِثْلَ عُشْبِ السُّطوحِ، الَّذى يَيْبَسُ قَبْل أنْ يُقْطَع. الَّذى لَمْ يَمْلأ الحاصِدُ مِنْهُ يَدَهُ، ولا الَّذى يَجْمَعُ الغُمورُ حُضْنَهُ. ولَمْ يَقُل المجْتازونَ إنَّ بَرَكَة الرَّبِّ عَلَيْكُم، وبارَكْناكُم باسْمِ الرَّبِّ. هَلِّلُيلويا. + +++",
  "129": "مِن الأعْماقِ صَرختُ إلَيكَ يا رَبُّ (†) مِن الأعْماقِ صَرختُ إلَيكَ يا رَبُّ. يا رَبُّ اسْمعْ صَوتى، لتكنْ أذُناكَ مُصْغيَتْينِ إلى صوت تَضرُّعى. إن كنتَ للآثامِ راصداً يا رَبُّ، يا رَبُّ مَن يَثبُتُ؟ لأنّ مِن عِندِكَ المَغفرَةَ. مِن أجل اسْمكَ صَبرتُ لكَ يا رَبُّ، تَمسّكتْ نَفسى بناموسِكَ. انْتظَرَتْ نَفسى الرّبَّ مِن مَحرسَ الصُبّحِ إلَى الليْلِ. مِن مَحرسِ الصُبّحِ فَلْينتَظِرْ إسرائيلُ الرّبَّ. لأنّ الرّحمةَ مِن عِندِ الرّبّ، عظيمٌ هو خلاصُهُ، وهو يَفتَدى إسْرائيلَ مِن كُلِّ آثامِهِ. هَلِّلُيلويا. + +++",
  "130": "يا رَبُّ لَمْ يَرْتَفِعْ قَلْبى يا رَبُّ لَمْ يَرْتَفِعْ قَلْبى ولَمْ تَسْتَعلِ عَيْناي، ولَمْ أسْلُكْ فى العَظائِمِ ولا فى العَجائِبِ. الَّتى هِىَ أَعْلَى مِنّى. أمّا إنْ كُنْتُ لَمْ أتَّضِعْ، لَكِنْ رَفعْتُ صَوْتى مِثْلُ الفَطيمِ مِنَ اللَّبَنِ عَلَى أمِّهِ، كَذَلكَ تَكونُ عَلَىَّ نَفْسى. فَلْيتَّكِلْ إسْرائيلُ عَلَى الرَّبِّ، مِنَ الآنَ وإلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "131": "اذْكُر يا رَبُّ داوُدَ وكُلّ مَذَلَّتِهِ اذْكُر يا رَبُّ داوُدَ وكُلّ مَذَلَّتِهِ. كَيْفَ أقْسَمَ للرَّبِّ، ونَذَرَ لإلَهِ يَعْقوبَ: إنّى لا أدْخُل إلَى مَسْكنِ بَيْتى، ولا أصْعَدُ عَلَى سَريرِ فِراشى. ولا أُعْطى نَوْماً لِعَيْنى، ولا نُعاساً لأجْفانى، ولا راحَةً لصدْغى. إلَى أنْ أجِدَ مَوْضِعاً لِلرَّبِّ، ومَسْكَناً لإلَهِ يَعْقوبَ. ها قَدْ سَمِعْنا بِهِ فى أفْراته، ووَجَدْناهُ فى مَوْضِعِ الغابةِ. لِنَدْخُل إلَى مَساكِنِهِ، ونَسْجدَ فى المَوْضِعِ الَّذى فيهِ اسْتَقَرَّتْ قَدماهُ. قُمْ يا رَبُّ إلَى راحَتكَ، أنْتَ وتابوتُ قُدْسِكَ. كَهَنتُكَ يَلْبَسونَ البِرَّ، وأبْرارُكَ يَبْتهِجونَ. مِنْ أجْلِ داوُدَ عَبدِكَ، لا تَردَّ وَجْهكَ عَنْ مَسيحِكَ. حَلفَ الرَّبُّ لِداوُدَ حَقًّا ولا يُخْلِف، لأجْعَلَنَّ مِنْ ثَمَرَةِ بَطْنِكَ عَلَى كُرْسيكَ. إنْ حَفِظَ بَنوكَ عَهْدى وشَهاداتى الَّتى أُعْلِمهُمْ إيّاها. فَبَنوهُم أيْضاً يَجْلِسونَ إلَى الأبَدِ عَلَى كُرسيكَ. لأنَّ الرَّبَّ اخْتار صِهْيونَ، وَرَضيها مَسْكَناً لَهُ: هَذا هُوَ مَوْضِعُ راحَتى إلَى أَبَدِ الأبَدِ، هَهُنا أسْكُنُ لأنّى أرَدْتُه. لِطَعامِها أُبارِكُ تَبْريكاً، لمَساكينِها أُشْبِعُ خُبْزاً. لكَهَنَتِها أُلْبِسُ الخَلاصَ، وأبْرارُها يَبْتَهِجونَ ابْتِهاجاً. هُناكَ أُقيمُ قَرناً لداوُدَ، هَيأتَ سِراجاً لِمَسيحى. لأعْدائِهِ أُلْبِسُ الخِزْىَ، وعَليْهِ تَزْدهِرُ قَداسَتى. هَلِّلُيلويا. + +++",
  "132": "هُوَذا ما أحْسَنَ وما أحْلَى هُوَذا ما أحْسَنَ وما أحْلَى أنْ يَسْكُن الأخْوَةُ مَعاً. كالطّيبِ الكائِنِ عَلَى الرَّأْسِ الَّذى يَنْزلُ عَلَى اللِّحْيةِ، لِحْيَة هَرونَ النّازِلةِ عَلَى جَيْبِ قَميصِه. ومِثْلُ نَدَى حَرْمونَ المنْحَدِر عَلَى جَبَل صِهْيونَ، لأنَّ هُناكَ أمَرَ الرَّبُّ بالبَرَكَةِ والْحَياةِ إلَى الأبَدِ. هَلِّلُيلويا. + +++",
  "133": "ها بارِكوا الرَّبَّ ها بارِكوا الرَّبَّ يا عَبيدَ الرَّبِّ القائِمينَ فى بَيْتِ الرَّبِّ في دِيارِ إلَهِنا. فى اللَّيالى ارْفَعوا أيْديَكُم إلَى القُدسِ، وبارِكوا الرَّبَّ. يُبارِككُم الرَّبُّ مِنْ صِهْيونَ، الَّذى خَلَقَ السَّمَوات والأرْضَ. هَلِّلُيلويا. + +++",
  "136": "عَلَى أنْهارِ بابِلَ عَلَى أنْهارِ بابِلَ هُناكَ جَلَسْنا، بَكَيْنا عِنْدَما تَذَكّرْنا صِهْيونَ. عَلَى الصِّفْصافِ فى وَسَطِها عَلَّقنا قيثاراتنا، لأنَّهُ هُناكَ سَألَنا الَّذينَ سَبَوْنا أقْوالَ التَّسْبيح. والَّذينَ اسْتاقونا إلَى هُناك قالوا: سَبِّحوا لَنا تَسْبِحَةً مِنْ تَسابيحِ صِهْيونَ. كَيفَ نُسَبِّحُ تَسْبِحَةَ الرَّبِّ فى أرْضٍ غَريبَةٍ؟ إنْ نَسيتُكِ يا أورُشَليمَ تنْسَي يَمينى، ويَلْتَصِقُ لِسانى بِحَنَكى إنْ لَمْ أذْكُرك، إنْ لَمْ أُفضِّلْ أورُشَليمَ عَلَى أَعْظَم فَرَحى. اذْكُرْ يا رَبُّ بَني أَدومَ فى يَومَ أورُشَليمَ القائِلينَ: انْقُضوا انْقُضوا حَتَى الأساسَ مِنْها. يا بِنْتَ بابِلَ الشَّقِيَّة، طوبَى لِمَنْ يُكافِئك مُكافأتكِ الَّتى جازَيتِنا. طوبَى لِمَنْ يُمْسِكُ أطْفالَكِ، ويَضْرِبُ بِهِمُ الصَّخْرةَ. هَلِّلُيلويا. + +++",
  "137": "اعْتَرِفُ لَكَ يا رَبُّ اعْتَرِفُ لَكَ يا رَبُّ مِنْ كُلِّ قَلْبى، لأنَّكَ اسْتَمعْتَ كُلَّ كَلِماتِ فَمى. أَمامَ الملائِكةِ أُرَتِّلُ لَكَ، وأسْجُدُ قُدّامَ هَيْكَلِكَ المقَدَّسِ، وأعْتَرِفُ لإسْمِكَ عَلَى رَحْمَتِكَ وحَقِّكَ، لأنَّكَ قَدْ عَظَّمْتَ اسْمَكَ القُدّوسَ عَلَى الكُلِّ. اليَومَ الَّذى أدْعوكَ فيهِ اجِبْنى بِسُرْعَةٍ، تُزَوِّدُ نَفْسى كَثيراً بِقُوَّةٍ. فَلْيَعْتَرِفْ لَكَ يا رَبُّ كُلُّ مُلوكِ الأرْضِ، لأنَّهُمْ سَمِعوا سائِرَ كَلِماتِ فَمِكَ. وليسبِّحوا فى طُرُقِ الرَّبِّ لأنَّ مَجْدَ الرَّبّ عَظيمٌ. لأنَّ الرَّبَّ عالٍ ويُعايِنُ المتواضِعينَ، أمّا المتَكبِّرونَ فَيَعْرِفهُم مِنْ بَعْد. إنْ سَلكْتُ فى وَسَطِ الشِّدَّةِ فَإنَّكَ تُحْيينى، عَلَى رِجْزِ الأعْداءِ مَدَدْتَ يَدَكَ وخَلصتنى يَمينك. الرَّبُّ يُجازى عَنّى. يارَبُّ رَحْمَتُكَ دائِمَةٌ إلَى الأبَدِ، أعْمالُ يَدَيْكَ يا رَبُّ لا تَتْرُكها. هَلِّلُيلويا. + +++",
  "140": "يا رَبُّ إليْكَ صَرخْتُ (†) يا رَبُّ إليْكَ صَرخْتُ فاسْتَمِعْ لى، انْصِتْ إلَى صَوْتِ تَضرُّعى إذا ما صَرخْتُ إليْكَ. لِتَسْتَقِمْ صَلاتى كالْبَخور قُدّامِكَ، ولِيَكُن رَفْعُ يَدىَّ كذبيحَةٍ مَسائِيَّةٍ. ضَعْ يا رَبُّ حافِظًاً لِفَمى، وباباً حَصيناً لشَفَتىَّ، ولا تُمِلْ قَلْبى إلَى كَلامِ الشَّرِّ، فَيُمارِسُ الْخَطايا مَعَ أُناسٍ فاعِلى الإثْمِ ولا أشْتَركُ فى ولائِمِهِمْ. فَلْيؤدِّبْنى الصِّدّيقُ برَحْمةٍ ويُوَبِّخنى، أمّا زَيْتُ الخاطئ فَلا يَدْهنُ رَأسى. لأنَّ صَلاتى أيْضًا ضِدَّ رَغَباتِهِم الشِّرّيرَةِ. ذُهِلَ أقْوياؤُهُم عِنْدَ الصَّخْرَةِ، يَسْمَعونَ كَلِماتى اللَّيِّنَةَ، مِثْل شَحْمِ الأرْضِ انْشَقوا عَلَى الأرْضِ. تَبَدَّدَت عِظامُهُمْ عِنْدَ الْجَحيمِ، لأنَّ عُيونَنا إليْكَ يا رَبُّ. يا رَبُّ عَليْكَ تَوكَّلْتُ فَلا تَقْتُل نَفْسى. احْفَظنى مِنَ الفخِّ الَّذى نَصَبوهُ لى، ومِنْ شُكوكِ فاعِلى الإثْمِ. يَسْقُطُ الْخُطاةُ فى شِباكِهِمْ وأكونُ أَنا وَحْدى حَتَّى يَجوز الإثْمُ. هَلِّلُيلويا. + +++",
  "141": "بصَوْتى إلَى الرَّبِّ صَرَخْتُ بصَوْتى إلَى الرَّبِّ صَرَخْتُ، بِصَوْتى إلَى الرَّبِّ تَضَرَّعْتُ أسْكُبُ أمامَه تَوَسُّلى، أبُثُّ لَدَيْهِ ضيقى عِنْدَ فَناءِ روحى مِنّى وأنْتَ عَلمتَ سُبُلى. فى الطَّريقِ الَّذى أسْلُكُ أخْفَوْا لى فَخّاً. تأمَّلْتُ عَنِ اليَمينِ وأبْصَرتُ، فلَمْ يَكُنْ مَنْ يَعْرفنى. ضاعَ الْمَهْرَبُ مِنّى ولَيْسَ مَنْ يَسْألُ عَنْ نَفْسى فَصَرخْتُ إليْكَ يا رَبُّ وقلْتُ: أنْتَ هُوَ رَجائى وحَظّى فى أرْضِ الأحْياءِ. أنْصِتْ إلَى طلبَتى، فإنّى قَدْ تَذلَّلْتُ جِدّاً. نَجِّنى مِنَ الَّذينَ يَضْطَهِدونى، لأنَّهُمْ قَدْ اعْتَزّوا أكثَرَ مِنّى. اخْرِجْ مِنَ الْحَبْسِ نَفْسى، لِكَى أشْكُرَ إسْمَكَ يا رَبُّ. إيّاى ينْتَظِرُالصِّدّيقونَ حَتَى تُجازينى. هَلِّلُيلويا. + +++",
  "142": "يارَبُّ إسْمَع صَلاتِى يا رَبُّ اسْمَع صَلاتِى. انْصِتْ إلى طَلبَتِى بَحَقِّكَ. اسْتَجبْ لى بَعدْلِكَ. ولا تدْخُلْ فى المحَاكَمةِ مَعَ عَبْدكَ، فإنَّهُ لَنْ يَتَزكَّى قُدَّامكَ كلُّ حَىِّ. لأنَّ العَدوَّ قدِ اضْطَهدَ نَفْسِى، وأذَلَّ فى الأرْضِ حَياتِى. أجْلسَنِى فى الظَلمَاتِ مِثْلَ الموْتَى مُنْذُ الدَّهرٍ. أضّجَرتْ فى رُوحى، اضْطَربَ فىَّ قَلْبِى. تذكَّرتُ الأيَّامَ الأولَى ولَهِجْتُ فى كلِّ أعْمالِكَ، وفى صَنائِع يَدَيْكَ كنْتُ أتَأمَّلُ. بَسَطتُ إليْكَ يَدىَّ، صَارتْ نَفْسِى لكَ مِثلُ أرْضٍ بِلا مَاءٍ. اسْتَجبْ لى يَا ربُّ عاجلاً فَقَد فَنِيتْ رُوحِى. لا تَحْجبْ وجْهَكَ عنِّى، فأشَابهُ الهابِطينَ فى الجُبِّ. فلأسْمَعْ فى الغَدَاةِ رحْمَتكَ، فإنِّى عَليكَ تَوكَّلتُ. عرِّفْنِى يا رَبُّ الطَّريقَ التى أسْلُكَ فِيهَا، لأنِّى إليْكَ رفَعْتُ نَفْسِى. أنْقِذْنِى مِنْ أعْدائِى يا رَبُّ، فإنِّى لجأْتُ إليْكَ. علِّمنِى أنْ أصْنَعَ مَشِيئتَكَ، لأنَّك أنْتَ هُو إلهِى. رُوحُكَ القُدُّوسُ فَليهْدنِى إلى الاسْتِقامَةِ. مِنْ أجْلِ إسْمِكَ يا ربُّ تُحْيِينِى، بَحَقِّكَ تُخْرِجُ مِنَ الشِّدَّةِ نَفْسى، وبرَحْمتِكَ تَسْتأصِلُ أعْدائِى، وتُهلِكَ جُميعَ مُضايقى نَفْسِى، لأنِّى أنَا هُو عَبْدكَ أنَا. هَلِّلُيلويا. + +++",
  "145": "سَبِّحى يا نَفْسى الرَّبَّ سَبِّحى يا نَفْسى الرَّبَّ. أُسَبِّحُ الرَّبَّ فى حَياتى، وأُرَتِّلُ لإلَهى مادُمتُ حَيّاً. لا تَتَّكِلوا عَلَى الرُّؤساءِ ولا عَلَى بَنى البَشَرِ. الَّذينَ لَيْسَ عِنْدهُمْ خَلاصٌ. تَخْرجُ روحُهُم فَيَعودونَ إلَى تُرابِهِمْ، فى ذَلِكَ اليَوْمِ تَهْلكُ كافَّةَ أفْكارِهِم. طوبَى لِمَنْ إلَهُ يَعْقوبَ مُعينُهُ، واتِّكالُهُ عَلَى الرَّبِّ إلَهِهِ. الَّذى صَنَعَ السَّماءَ والأرْضَ والبَحْرَ وكُلَّ ما فيها. الحافِظِ العَدْل إلَى الدَّهْرِ. الصّانِعِ الْحُكْمِ للمَظْلومينَ. المعْطى الطَّعامَ للجِياعِ. الرَّبُّ يَحلُّ المأْسورينَ، الرَّبُّ يُقيمُ السّاقِطينَ. الرَّبُّ يُحَكِّم العُمْيانَ، الرَّبُّ يُحِبُّ الصِّدّيقينَ. الرَّبُّ يَحْفَظُ الغُرباءَ ويعضدُ اليَتيمَ والأرْمَلةَ، ويُبيدُ طُرقَ الْخُطاةِ. يَمْلكُ الرَّبُّ إلَى الدَّهْرِ، وإلَهُكِ يا صِهْيونُ مِنْ جيلٍ إلَى جيلٍ. هَلِّلُيلويا. + +++",
  "146": "سَبِّحوا الرَّبَّ فإنَّ المزْمورَ جَيِّدٌ سَبِّحوا الرَّبَّ فإنَّ المزْمورَ جَيِّدٌ، لإلَهِنا يَلذُّ التَّسْبيحُ. الرَّبُّ يَبْنى أورُشَليمَ، الرَّبُّ يَجْمعُ مُتَفرِّقى إسْرائيلَ. الرَّبُّ يَشْفى مُنْكَسِرى القُلوبِ، ويُجبرُ جَميعَ كَسْرهِمْ. الْمُحْصى كَثْرةَ الكَواكِبِ، ولكافَّتِها يُعْطى أسْماء. عَظيمٌ هُوَ الرَّبُّ وعَظيمَةٌ هِىَ قُوَّتُهُ، ولا إحْصاء لِفهْمِهِ. الرَّبُّ يَرْفَعُ الوُدَعاءَ، ويُذِلُّ الْخُطاةَ إلَى الأرْضِ. ابْتَدِئُوا للرَّبِّ بالاعْتِراف، رَتِّلوا لإلَهِنا بالقيثارَةِ. الَّذى يُجَلِّلُ السَّماءَ بالغَمامِ، الَّذى يُهَيّئ للأرْضِ المطَرَ. الَّذى يُنبتُ العُشْبَ عَلَى الْجِبالِ، والْخُضْرةِ لِخِدْمَةِ البَشَرِ، ويُعْطى البَهائِمَ طَعامَها ولِفِراخِ الغِرْبانِ الَّتى تَدْعوهُ لا يُؤْثرُ قُوَّةَ الْخَيْل، ولا يُسَرُّ بِساقى الرَّجُل، بَلْ يُسَرُّ الرَّبُّ بِخائِفيهِ، وبالرّاجينَ رَحْمتَهُ. هَلِّلُيلويا. + +++",
  "147": "سَبِّحى الرَّبَّ يا أورُشَليمَ (†) سَبِّحى الرَّبَّ يا أورُشَليمَ، سَبِّحى إلَهَكِ يا صِهْيونَ. لأنَّهُ قَدْ قَوَّى مَغاليقَ أبْوابِكِ، وبارَكَ بَنيكِ فيكِ. الَّذى جَعَلَ تُخومَكِ فى سَلامٍ، ويُشْبِعُكِ مِنْ شَحْم الْحِنْطَةِ. الَّذى يُرْسِلُ كَلِمَتَهُ إلَى الأرْضِ، فَيُسْرعُ قَولُه عاجِلاً جِدًّاً. المعْطى الثَّلْجَ كالصّوفِ، المذَرِى الضَّبابَ كالرَّمادِ. ويُلْقى الْجَليدَ مِثْل الفُتاتِ، قُدّامَ وَجْه بردِهِ مَنْ يَقومُ؟ يُرْسِلُ كَلمَتَه فَتُذيبَهُ، تَهبُّ ريحُهُ فَتَسيلُ المياهَ، المخبرُ كَلمتَهُ لِيَعْقوبَ، وفَرائِضَهُ وأَحْكامَهُ لإسْرائيلَ. لَمْ يَصْنَع هَكَذا بكلِّ الأممِ، وأحْكامَهُ لَمْ يُوَضِّحها لَهُمْ. هَلِّلُيلويا. + +++"
};
